import type { Drill } from "./types";

// Public service / mid drills, keyed by module slug — 25 per module.
// Public-sector supervisor / sergeant / program manager: policy rollouts, inter-agency
// coordination, staffing, complaints, debriefs, memos up to directors. Merged into course.ts.
export const PUBLICSERVICE_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-gov-mid-01","level":"mid","profession":"publicservice","title":"The briefing note that buries the ask","scenario":"You're sending your director a briefing note on the permit-processing backlog. The real point: you need approval for two temporary staff by Friday or the service standard slips next quarter. Your draft opens with three paragraphs of program history.","task":"Write the opening 1-2 sentences of the note with the ask and deadline first.","tips":["Sentence one: what you need approved and by when.","History and volumes become supporting context below.","Directors triage by the first line — make it carry the decision."],"focus":["clarity","impact"],"placeholder":"Requesting approval for two temporary staff by Friday —"},
    {"id":"lead-gov-mid-02","level":"mid","profession":"publicservice","title":"The shift briefing with the alert in the middle","scenario":"You're briefing the incoming shift. Most of it is routine, but there's one live issue: a facility alarm system is down and rounds must be doubled overnight. Your notes have it buried between parking updates and a training reminder.","task":"Write the first two sentences of the briefing so the live issue leads.","tips":["Open with the one thing that changes how they work tonight.","Routine items follow in any order — the alert cannot.","Say what to do, not just what's broken."],"focus":["structure","clarity"],"placeholder":"One thing changes tonight: the alarm system in Building C is down, so —"},
    {"id":"lead-gov-mid-03","level":"mid","profession":"publicservice","title":"The inter-agency data request","scenario":"You need caseload data from a partner agency to finish a joint report due in two weeks. Your draft email spends four sentences on the report's background before mentioning you need anything from them.","task":"Write a 2-3 sentence email that puts the request and date in sentence one.","tips":["Lead with what you need, from whom, and by when.","One line of context is enough — they know the joint report exists.","End with how to send it or who to contact."],"focus":["clarity","concision"],"placeholder":"Could your team send Q1-Q2 caseload counts by June 20?"},
    {"id":"lead-gov-mid-04","level":"mid","profession":"publicservice","title":"The incident notification upward","scenario":"A member of the public was injured in a slip at your facility this morning. First aid was given, the person declined transport, and the hazard is cordoned off. Your draft to the director walks through the timeline before stating the outcome.","task":"Write a 2-3 sentence notification that leads with what happened and the current status.","tips":["First sentence: the incident, the outcome, the current state.","Timeline detail is support — attach or append it.","Say what happens next: report filed, hazard assessment booked."],"focus":["clarity","structure"],"placeholder":"A visitor slipped at the main entrance this morning; minor injury, treated on site, hazard cordoned."},
    {"id":"lead-gov-mid-05","level":"mid","profession":"publicservice","title":"The staffing shortfall flag","scenario":"Two of your twelve staff resigned this month and a third starts parental leave in six weeks. Coverage breaks in August unless recruitment starts now. Your draft to the director eases in with a review of the unit's workload trends.","task":"Write a heads-up message that leads with the shortfall and the decision needed.","tips":["Lead with the number and the date coverage breaks.","The decision you need: authority to post the positions now.","Trends explain the ask — they come second."],"focus":["impact","precision"],"placeholder":"We lose coverage in August: two resignations plus a parental leave. I need authority to post now."},
    {"id":"lead-gov-mid-06","level":"mid","profession":"publicservice","title":"The councillor's office inquiry","scenario":"A councillor's assistant emails asking why a resident's tree-removal request has taken four months. The answer: it's approved, and the crew is scheduled for next week. Your draft opens by explaining the assessment process.","task":"Write a 2-3 sentence reply that gives the resolution first.","tips":["Lead with the news they can relay: approved, scheduled next week.","Process explanation is optional support, kept to one line.","A fast, front-loaded answer builds trust with that office."],"focus":["clarity","audience"]},
    {"id":"lead-gov-mid-07","level":"mid","profession":"publicservice","title":"The policy rollout announcement","scenario":"A new records-retention procedure takes effect Monday and changes how your team closes files. Your draft announcement opens with why the policy was revised at the corporate level. Your team just needs to know what to do differently and from when.","task":"Write the first two sentences of the announcement, leading with the change and the date.","tips":["Sentence one: what changes and when it starts.","The corporate rationale is one sentence, later.","Point to where the full procedure lives."],"focus":["clarity","audience"],"placeholder":"Starting Monday, closed files must be —"},
    {"id":"lead-gov-mid-08","level":"mid","profession":"publicservice","title":"The overtime overrun heads-up","scenario":"Your unit's overtime spend is at 140% of budget with five months left in the fiscal year, driven by vacancies you've already flagged. Your director hates surprises at year-end. Your draft opens with a month-by-month recap.","task":"Write a 2-3 sentence message that states the overrun and the projected year-end position first.","tips":["Lead with the number now and the number at year-end if nothing changes.","One sentence on the driver — vacancies, already flagged.","Close with the option you recommend."],"focus":["precision","impact"],"placeholder":"Overtime is at 140% of budget; on current trend we end the year $85K over."},
    {"id":"lead-gov-mid-09","level":"mid","profession":"publicservice","title":"The contractor deliverable chase","scenario":"Your maintenance contractor missed the June inspection report for the third month running, and the contract lets you withhold payment. You want the report within five business days. Your draft email reads like an apology.","task":"Write a 2-3 sentence email that leads with the requirement and the date.","tips":["Sentence one: the report is overdue and is required within five business days.","Cite the contract clause once, without lecturing.","State the consequence plainly: payment holds until received."],"focus":["clarity","impact"],"placeholder":"The June inspection report is now three weeks overdue; please deliver it within five business days."},
    {"id":"lead-gov-mid-10","level":"mid","profession":"publicservice","title":"The grantee non-compliance memo","scenario":"A grant recipient has missed two quarterly reports, and the funding agreement requires you to recommend suspension or an extension to your director. You recommend a 30-day extension with conditions. Your draft memo describes the grantee's programming for a page first.","task":"Write the memo's opening sentence with your recommendation up front.","tips":["Open with the recommendation and the condition attached to it.","The grantee's history supports the call — it isn't the call.","Directors sign faster when the decision is sentence one."],"focus":["structure","clarity"],"placeholder":"I recommend a 30-day reporting extension for Riverside Community Services, conditional on —"},
    {"id":"lead-gov-mid-11","level":"mid","profession":"publicservice","title":"The verbal sitrep","scenario":"You're supervising the response to a burst water main affecting a seniors' residence. The duty director calls for a status update. You have thirty seconds and a habit of starting from when the call first came in.","task":"Say a 3-4 sentence sitrep that leads with current status and the next decision point.","tips":["First sentence: situation now — contained or not, who's affected.","Then: what's being done and what you need, if anything.","The origin story can wait for the debrief."],"focus":["clarity","structure"],"placeholder":"Status now: water is off to the building, 40 residents relocated to the common hall —"},
    {"id":"lead-gov-mid-12","level":"mid","profession":"publicservice","title":"The equipment approval request","scenario":"Your team's two radios out of eight are failing, and replacements cost $3,200 from an existing budget line. You have signing authority up to $2,000, so you need your director's approval. Your draft explains radio technology before making the ask.","task":"Write a 2-3 sentence approval request with the ask and amount in sentence one.","tips":["Lead with the approval you need and the dollar figure.","One line on why: failure rate and the safety implication.","Name the budget line so approval is one reply."],"focus":["clarity","concision"],"placeholder":"Requesting your approval for $3,200 to replace two failed radios from the equipment line."},
    {"id":"lead-gov-mid-13","level":"mid","profession":"publicservice","title":"The records request update","scenario":"The access-to-information coordinator asked whether your unit's records for a request are ready. They are — 240 pages, reviewed, with one section flagged for a possible exemption. Your draft describes your search methodology first.","task":"Write a 2-3 sentence reply that leads with the status the coordinator needs.","tips":["Lead with: records ready, page count, one flag.","The flag matters to their next step — name it specifically.","Methodology goes in the file, not the email."],"focus":["clarity","precision"],"placeholder":"Records are ready: 240 pages, reviewed, with one section flagged for the s.19 exemption."},
    {"id":"lead-gov-mid-14","level":"mid","profession":"publicservice","title":"The complaint resolution letter","scenario":"A resident complained that their service request was closed without action. You investigated: it was closed in error, the work is now scheduled for the 15th, and the process gap is fixed. Your draft letter opens with a paragraph about the department's commitment to service.","task":"Write the letter's first two sentences, leading with the outcome.","tips":["Sentence one: you were right, it was our error, here's the fix and date.","Commitment language means nothing before the outcome; a little after it.","Apologize once, specifically."],"focus":["clarity","audience"],"placeholder":"You were right — your request was closed in error. The work is now scheduled for July 15."},
    {"id":"lead-gov-mid-15","level":"mid","profession":"publicservice","title":"The personnel meeting request","scenario":"You need 30 minutes with your director this week to discuss a formal performance issue with one of your staff before you start the documented process. Your draft message hints vaguely at 'a sensitive team matter sometime soon.'","task":"Write a meeting request that states the purpose, the time needed, and the urgency plainly.","tips":["Name the topic at the level of detail email can carry: a performance matter needing direction.","Say 30 minutes, this week, and why the timing matters.","Vague requests get scheduled last."],"focus":["clarity","precision"],"placeholder":"Could I get 30 minutes this week? I need your direction on a staff performance matter before I begin the formal process."},
    {"id":"lead-gov-mid-16","level":"mid","profession":"publicservice","title":"The interagency meeting recap","scenario":"You chaired a three-agency coordination meeting on the encampment response. The one outcome that matters: each agency committed a named liaison by Friday. Your recap email drafts as chronological minutes.","task":"Write the recap's opening 1-2 sentences, leading with the commitment made.","tips":["Lead with the decision and the deadline everyone agreed to.","Minutes-style detail can follow or attach.","Name the action holders — commitments without names evaporate."],"focus":["structure","impact"],"placeholder":"Outcome from today: each agency names its encampment liaison to me by Friday."},
    {"id":"lead-gov-mid-17","level":"mid","profession":"publicservice","title":"The recommendation buried in options","scenario":"Your director asked which of three fleet-renewal options to take to the budget committee. You've analyzed all three and Option B is clearly right. Your draft presents A, B, and C neutrally for two pages and states no preference.","task":"Write an opening sentence that states your recommendation, then frames the options as support.","tips":["Sentence one: recommend Option B and the single strongest reason.","The comparison table earns its keep as evidence, not as the answer.","You were asked for a pick — give one."],"focus":["clarity","impact"],"placeholder":"I recommend Option B — staged replacement over three years — because —"},
    {"id":"lead-gov-mid-18","level":"mid","profession":"publicservice","title":"The facility closure notice","scenario":"The community pool closes for emergency repairs from Monday for approximately three weeks. You're drafting the public notice. Your draft opens with background on the mechanical inspection program.","task":"Write the notice's first two sentences: what's closing, when, and what residents should do.","tips":["Residents scan for: closed when, reopens when, alternatives where.","Inspection background is one line at most.","Put the alternative location early — it's the actionable part."],"focus":["audience","clarity"],"placeholder":"Riverside Pool will close Monday, July 7 for emergency repairs, reopening in approximately three weeks."},
    {"id":"lead-gov-mid-19","level":"mid","profession":"publicservice","title":"The weekly ops report opener","scenario":"Your weekly report to the director covers response times, staffing, and complaints. This week's headline: response times returned to standard for the first time in two months. Your draft opens with the staffing table as usual.","task":"Write a one-sentence opener that leads with the week's most important result.","tips":["The template order isn't the importance order — lead with the news.","One number makes the headline concrete.","Standing sections follow in their usual places."],"focus":["structure","impact"]},
    {"id":"lead-gov-mid-20","level":"mid","profession":"publicservice","title":"The safety hazard escalation","scenario":"During a site visit you found a damaged guardrail on a public stairway. You've taped it off, but repair needs facilities and the risk is real if the tape is ignored. Your draft to facilities describes your site visit agenda first.","task":"Write a 2-3 sentence escalation that leads with the hazard and the action needed.","tips":["First sentence: the hazard, the location, the interim control.","The ask: repair priority and a timeframe.","Site-visit context is irrelevant to the fix — cut it."],"focus":["clarity","impact"],"placeholder":"Damaged guardrail on the Oak Street stairway — taped off, but it needs repair this week."},
    {"id":"lead-gov-mid-21","level":"mid","profession":"publicservice","title":"The compliance deadline reminder","scenario":"Six of your fourteen staff haven't completed mandatory privacy training due in ten days, and non-completion gets escalated to HR with your name on it. Your draft reminder buries the deadline under a paragraph on why privacy matters.","task":"Write a 2-sentence reminder that leads with the deadline and who it applies to.","tips":["Sentence one: the training, the date, the 'if you haven't yet.'","One sentence on the consequence — escalation is automatic.","Skip the values lecture; they've heard it."],"focus":["clarity","concision"],"placeholder":"Privacy training closes July 12 — six of you still need to complete it."},
    {"id":"lead-gov-mid-22","level":"mid","profession":"publicservice","title":"The yes-with-a-condition answer","scenario":"Another unit's supervisor asks whether your team can cover their front counter Thursday afternoon. You can — if they cover your Friday morning rotation in return. Your draft explains your scheduling constraints for a paragraph before answering.","task":"Write a reply that answers in the first three words, then states the condition.","tips":["'Yes, if —' is a complete first clause.","The condition is the message; the scheduling backstory isn't.","Make accepting easy: propose the exact swap."],"focus":["concision","clarity"],"placeholder":"Yes — if you can cover our Friday morning rotation in exchange."},
    {"id":"lead-gov-mid-23","level":"mid","profession":"publicservice","title":"The debrief summary line","scenario":"You ran the debrief after a chaotic evacuation drill. The main finding: the assembly-point count took 22 minutes because floor wardens had no shared roster. Your summary email drafts as a narrative of the whole drill.","task":"Write the summary's opening sentence: the finding and the fix, up front.","tips":["Lead with the one finding that must change before the next drill.","The narrative is for the appendix.","Pair every finding with an owner and a date."],"focus":["structure","precision"],"placeholder":"Main finding: the assembly count took 22 minutes because wardens had no shared roster — fix owned by —"},
    {"id":"lead-gov-mid-24","level":"mid","profession":"publicservice","title":"The schedule change announcement","scenario":"Starting next month, weekend coverage moves from voluntary sign-up to a rotating assignment, a change some staff will dislike. Your draft opens with two paragraphs justifying the decision before stating what it is.","task":"Write the first two sentences: the change and its start date first, one reason second.","tips":["State the change plainly before defending it — burying it reads as evasive.","One honest reason beats three padded ones.","Say where questions go: your door, this week."],"focus":["clarity","impact"],"placeholder":"Starting August 1, weekend coverage moves to a rotating assignment."},
    {"id":"lead-gov-mid-25","level":"mid","profession":"publicservice","title":"The comms office turnaround","scenario":"The communications office needs a one-line answer within the hour: is the road reopening tomorrow, yes or no? It is, weather permitting. Your draft reply describes the resurfacing work completed this week.","task":"Write a one-sentence reply that answers the question with its one real caveat.","tips":["Answer first: yes, tomorrow.","Attach the single caveat that could change it — nothing else.","Comms needs a quotable line, not an engineering report."],"focus":["concision","precision"],"placeholder":"Yes — Maple Road reopens tomorrow at 6 a.m., weather permitting."}
  ],
  "start-with-the-audience": [
    {"id":"audience-gov-mid-01","level":"mid","profession":"publicservice","title":"The new records system, for the counter staff","scenario":"IT announced the new case-management system with an email full of 'data migration windows' and 'legacy read-only access.' Your frontline counter staff just need to know what changes when a resident is standing in front of them on Monday.","task":"Write a 3-4 sentence team message that translates the rollout into what changes at the counter.","tips":["Start from their Monday morning, not the project plan.","Translate 'legacy read-only' into 'you can look up old files but not edit them.'","Name who to call when the screen does something unexpected."],"focus":["audience","clarity"],"placeholder":"From Monday, you'll open new requests in the new system. Two things change at the counter:"},
    {"id":"audience-gov-mid-02","level":"mid","profession":"publicservice","title":"The road closure, for the residents","scenario":"You're drafting the notice for a six-week watermain replacement on a residential street. Your engineering source material talks about 'staged excavation' and 'service interruptions of limited duration.' Residents want to know: can I park, can I get out of my driveway, will my water stop.","task":"Write a 3-4 sentence notice answering the three questions residents actually have.","tips":["List their questions first, then answer only those.","'Service interruptions of limited duration' means 'water off for up to 4 hours, with 24 hours' notice' — say that.","One line on where to complain or ask."],"focus":["audience","precision"],"placeholder":"Between July 8 and August 15, crews will replace the watermain on Elm Street. Here's what it means for you:"},
    {"id":"audience-gov-mid-03","level":"mid","profession":"publicservice","title":"The director wants altitude, not process","scenario":"Your director asked how the intake modernization is going. You're deep in the weeds: form redesign, staff training modules, a vendor delay on the scanning module. What the director needs is whether it lands on time, on budget, and what needs their attention.","task":"Write a 2-3 sentence update pitched at director altitude.","tips":["Directors act on: timeline, money, decisions needed. Lead there.","One weed maximum — the vendor delay, because it threatens the date.","Save the training-module detail for your own tracker."],"focus":["audience","concision"],"placeholder":"Intake modernization is on budget and two weeks behind — recoverable if —"},
    {"id":"audience-gov-mid-04","level":"mid","profession":"publicservice","title":"Arming the counter for citizen questions","scenario":"A fee increase takes effect next month and your counter staff will absorb the public's reaction. They don't need the fiscal rationale you got in the briefing — they need a short, honest answer they can say to a frustrated resident without escalating.","task":"Write the 2-3 sentence answer you want every staff member to give at the counter.","tips":["Write it in the voice of the person saying it, aloud.","Acknowledge the increase plainly — dodging enrages.","Give staff the one thing they can offer: where the fee schedule and appeal info live."],"focus":["audience","clarity"]},
    {"id":"audience-gov-mid-05","level":"mid","profession":"publicservice","title":"The acronym-free onboarding note","scenario":"A new hire starts Monday. Your usual welcome note references the DSR queue, the T-4 room, 'the Wednesday sync,' and 'flagging through the portal' — none of which means anything to someone on day one.","task":"Rewrite a 3-4 sentence first-day note that assumes zero internal vocabulary.","tips":["Every acronym gets expanded or cut.","Anchor to things a stranger can find: a room number, a person's name, a time.","Tell them the one thing to do first, not everything at once."],"focus":["audience","clarity"]},
    {"id":"audience-gov-mid-06","level":"mid","profession":"publicservice","title":"The complaint reply without the codes","scenario":"A resident complained their noise report 'was ignored.' Internally, the file shows it was triaged P3, attended once with no violation observed, and closed per SOP 12-4. None of that language can go in your reply — but the substance must.","task":"Write a 3-4 sentence reply that explains what happened in the resident's terms.","tips":["Translate the file: 'an officer attended on June 3 and did not observe a violation.'","Never quote SOP numbers at the public.","End with what they can do if it recurs — the actionable part."],"focus":["audience","clarity"],"placeholder":"Your report wasn't ignored — an officer attended on June 3. Here's what happened:"},
    {"id":"audience-gov-mid-07","level":"mid","profession":"publicservice","title":"The delay, framed for the partner agency","scenario":"Your unit's data submission to a partner agency will be two weeks late because of a system migration. Drafting the note, you keep explaining your migration. What the partner cares about is their downstream deadline and whether a partial extract would hold them over.","task":"Write a 2-3 sentence note framed around the partner's deadline, not your system.","tips":["Open with the impact on them: new date, and what it does to their timeline.","Offer the partial extract — it's the part they can use.","Your migration gets half a sentence."],"focus":["audience","impact"],"placeholder":"Our data submission will reach you July 18 instead of July 4. To keep your report on track, we can —"},
    {"id":"audience-gov-mid-08","level":"mid","profession":"publicservice","title":"Reporting requirements for a tiny nonprofit","scenario":"A first-time grantee — a two-person community group — must file quarterly reports. The funding agreement's language ('outcome indicators disaggregated by demographic cohort') will bury them. You need them to succeed, not lawyer up.","task":"Write a 3-4 sentence plain-language explanation of what they actually have to send you each quarter.","tips":["Convert each clause into a concrete item: 'how many people attended, roughly broken down by age group.'","Name the format that's acceptable — a simple table is fine, say so.","Offer the 15-minute call; for this audience it prevents a quarter of confusion."],"focus":["audience","clarity"]},
    {"id":"audience-gov-mid-09","level":"mid","profession":"publicservice","title":"The new reporting rule, for the shift","scenario":"A new use-of-force reporting requirement comes down from headquarters wrapped in policy language. Your officers will hear it as more paperwork. What it actually means for them: one extra form, only in specific situations, and it protects them when their account is on record early.","task":"Write a 3-4 sentence briefing that translates the policy into what it means on their shift.","tips":["Lead with the practical scope: when the form applies and when it doesn't.","Name the benefit to them honestly — early documented accounts protect officers.","Don't oversell; they'll test every claim against reality."],"focus":["audience","impact"],"placeholder":"Bottom line for your shift: one new form, and only when —"},
    {"id":"audience-gov-mid-10","level":"mid","profession":"publicservice","title":"One outage, two audiences","scenario":"The online booking system is down, likely all day. Staff need workarounds and script guidance; the public needs a short notice on the website. You have to write both — and the drafts keep bleeding into each other.","task":"Write the 1-2 sentence public notice, then the 2-3 sentence staff version, keeping each pure to its audience.","tips":["Public: what's down, the alternative, when to check back. No internal cause.","Staff: the workaround, the script line, who's fixing it.","If a sentence serves neither reader fully, it serves no one."],"focus":["audience","structure"]},
    {"id":"audience-gov-mid-11","level":"mid","profession":"publicservice","title":"Legal advice into staff instruction","scenario":"Counsel sent you three paragraphs on how staff must handle requests involving minors, hedged with 'generally,' 'absent exceptional circumstances,' and citations. Your staff need a rule they can apply at 4:55 p.m. on a Friday.","task":"Write a 2-3 sentence operational instruction that preserves the legal substance in usable form.","tips":["Turn the hedge into a rule plus an escalation path: 'do X; if Y, call me before proceeding.'","Cut citations; keep the one condition that changes the answer.","Test it: could a new hire follow this without calling counsel?"],"focus":["audience","precision"],"placeholder":"Rule: for any request involving a minor, do X. The one exception:"},
    {"id":"audience-gov-mid-12","level":"mid","profession":"publicservice","title":"The sign people will actually read","scenario":"You need signage for a facility entrance where a new check-in step starts Monday. Your first draft: 'Pursuant to updated visitor management protocols, all visitors are required to register at the kiosk prior to proceeding.' People walk past signs like that.","task":"Rewrite the sign in one or two short lines a hurried visitor will follow.","tips":["Imperative, second person, under ten words if possible.","'Pursuant to protocols' has never stopped anyone at a door.","Say the action, then the where: 'Check in at the kiosk first.'"],"focus":["audience","concision"],"placeholder":"Please check in at the kiosk before entering."},
    {"id":"audience-gov-mid-13","level":"mid","profession":"publicservice","title":"The aide who isn't a specialist","scenario":"A councillor's aide calls asking how the rent-support program 'actually works' for a constituent. You could recite eligibility criteria and adjudication stages. The aide needs enough to guide one person: can they apply, how, and how long it takes.","task":"Write a 3-4 sentence explanation pitched for the aide to relay to the constituent.","tips":["Answer the constituent's path: qualify, apply, wait time.","Skip the adjudication machinery entirely.","Give the aide one direct contact for the hard cases — that's what they'll remember you for."],"focus":["audience","clarity"]},
    {"id":"audience-gov-mid-14","level":"mid","profession":"publicservice","title":"The volunteer call-out","scenario":"You need eight volunteers for the weekend heat-response canvass. Your draft reads like an operations order: shift blocks, deployment zones, reporting structure. Volunteers respond to purpose and simplicity, not logistics.","task":"Write a 3-4 sentence call-out that leads with the purpose and makes signing up one step.","tips":["First line: what their two hours accomplishes for a real person.","Logistics collapse to: when, where to show up, one link to sign up.","Warm but not gushing — respect their time both ways."],"focus":["audience","impact"],"placeholder":"This weekend we're checking on 300 seniors during the heat warning — and we need eight more people."},
    {"id":"audience-gov-mid-15","level":"mid","profession":"publicservice","title":"The union rep conversation","scenario":"You're introducing a schedule change and need to walk the union rep through it before the team hears. Your management framing — coverage efficiency, service standards — is real, but the rep's frame is member impact: hours, seniority, notice.","task":"Write the 3-4 sentence opening of that conversation, framed on member impact first.","tips":["Answer their questions before they ask: whose hours change, how seniority applies, how much notice.","Efficiency rationale comes second — it's your reason, not their concern.","Flag what's still open to input; reps engage when there's something to shape."],"focus":["audience","clarity"]},
    {"id":"audience-gov-mid-16","level":"mid","profession":"publicservice","title":"The scope conversation without procurement-speak","scenario":"You're briefing a landscaping contractor's crew lead on added work at a park. Your draft is full of 'change order,' 'as per Schedule B,' and 'deficiency rectification.' The crew lead needs to know what to do, where, by when, and what gets checked.","task":"Write a 3-4 sentence instruction in the crew lead's terms.","tips":["Concrete nouns: the north slope, the drainage bed, Friday.","Say what you'll inspect and when — that's 'deficiency rectification' translated.","Keep the contract language for the paper trail, not the conversation."],"focus":["audience","precision"]},
    {"id":"audience-gov-mid-17","level":"mid","profession":"publicservice","title":"The FAQ answer on wait times","scenario":"The most-asked question on your program's page: 'How long does a permit take?' The honest answer is 'it depends' — 10 days for simple ones, 8 weeks for ones needing review. Your current FAQ says 'processing times vary based on application complexity.'","task":"Rewrite the FAQ answer in 2-3 sentences that give real numbers and help readers place themselves.","tips":["'Varies by complexity' answers nothing — give both numbers and what puts you in each lane.","Let readers self-sort: 'if your project includes X, expect the longer track.'","Add the one thing that speeds it up: a complete application."],"focus":["audience","precision"],"placeholder":"Most permits take about 10 business days. Yours may take up to 8 weeks if —"},
    {"id":"audience-gov-mid-18","level":"mid","profession":"publicservice","title":"Pick your primary reader","scenario":"You're announcing that the mobile outreach van adds a second weekly stop. You're tempted to write one message for everyone: the team who staffs it, the director who funded it, and the agencies who refer clients. Each cares about something different, and the blend serves none of them.","task":"Choose ONE primary audience and write a 2-3 sentence version aimed squarely at them.","tips":["Name your reader before you write a word.","The team needs the roster impact; agencies need the referral details; the director needs the outcome story.","Send the other audiences their own version later — shorter than you think."],"focus":["audience","structure"]},
    {"id":"audience-gov-mid-19","level":"mid","profession":"publicservice","title":"The stats, packaged for the journalist","scenario":"Comms forwards a journalist's question: have shelter turn-aways increased this winter? Your data says yes — turn-aways rose 18% while capacity was flat. Comms needs it from you in language that survives being quoted, with the context that keeps it honest.","task":"Write a 2-3 sentence response for comms that a non-specialist reader will understand correctly.","tips":["Give the number with its base: 18% more turn-aways, capacity unchanged.","Add the one piece of context that prevents misreading — seasonal comparison, not raw monthly.","Assume every sentence gets quoted alone; make each survivable."],"focus":["audience","precision"]},
    {"id":"audience-gov-mid-20","level":"mid","profession":"publicservice","title":"What the unit does, for a school group","scenario":"A grade-nine class is touring the facility and you have two minutes to explain what your emergency-management unit actually does. Your usual line — 'coordinating multi-agency response through the incident command framework' — will lose them in five words.","task":"Write a 3-4 sentence explanation a fourteen-year-old finds concrete and interesting.","tips":["Start from a scenario they can picture: the ice storm, the flood on the news.","Replace the framework with what people in this room actually do that day.","One vivid concrete detail beats three abstractions."],"focus":["audience","impact"]},
    {"id":"audience-gov-mid-21","level":"mid","profession":"publicservice","title":"The eligibility rule, in plain language","scenario":"The subsidy eligibility rule reads: 'Applicants must demonstrate household income not exceeding 80% of area median income, adjusted for household size.' You're writing the plain-language version for the application guide, where most applicants read at a grade-8 level.","task":"Rewrite the rule in 1-2 sentences an applicant can apply to their own situation.","tips":["Turn the formula into a lookup: 'check the table for your family size.'","'Demonstrate' means 'show us a document' — name which one.","Plain language isn't dumbed down; it's the same rule made usable."],"focus":["audience","clarity"],"placeholder":"You can apply if your household earns less than the amount shown for your family size in the table below."},
    {"id":"audience-gov-mid-22","level":"mid","profession":"publicservice","title":"The scheduling system, as staff actions","scenario":"HR's announcement of the new shift-bidding system explains modules and go-live phases. What your team needs is three actions: set up your profile by a date, enter your preferences by a date, and check your assignment on a date. Miss the first and the system defaults their schedule.","task":"Write a 3-4 sentence team message organized around the three actions and dates.","tips":["Actions and dates ARE the message; the system tour is a link.","Lead with the consequence of missing step one — that's what makes people move.","Three numbered lines beat three paragraphs."],"focus":["audience","structure"],"placeholder":"Three things to do in the new shift system — miss the first and it assigns your schedule for you:"},
    {"id":"audience-gov-mid-23","level":"mid","profession":"publicservice","title":"The cross-department memo","scenario":"You're asking three other departments to designate flood-season contacts. Your draft uses your unit's shorthand — 'EOC activation,' 'Level 2 events,' 'the duty roster' — which reads as noise to a parks administrator or a finance manager.","task":"Rewrite the request in 2-3 sentences any department head can act on without translation.","tips":["Say what a 'contact' will actually be asked to do, in hours and tasks.","'Level 2 event' becomes 'flooding that affects more than one neighbourhood.'","The easier the request is to picture, the faster you get names."],"focus":["audience","clarity"]},
    {"id":"audience-gov-mid-24","level":"mid","profession":"publicservice","title":"The emergency instruction","scenario":"A boil-water advisory hits three neighbourhoods tonight. You're drafting the alert. Every instinct says explain the cause — the pressure loss, the testing protocol. The public needs the action first: boil for one minute before drinking, until further notice.","task":"Write a 2-3 sentence alert with the action first and only essential context after.","tips":["Action, area, duration — in that order, in that sentence.","Cause gets a clause, not a paragraph.","Say how they'll know it's over; it stops the phone lines flooding."],"focus":["audience","clarity"],"placeholder":"If you live in Riverdale, Hillcrest, or Eastgate: boil tap water for one minute before drinking or cooking, effective now."},
    {"id":"audience-gov-mid-25","level":"mid","profession":"publicservice","title":"Selling the why of an unpopular step","scenario":"Staff hate the new double-verification step on cash handling — it adds two minutes to every transaction. The real reason it exists: last year's audit found a gap that put an employee under suspicion for weeks before records cleared them. That story is the why.","task":"Write a 3-4 sentence explanation to the team that connects the step to what it protects for them.","tips":["Frame the rule from their side: it protects the person handling the cash.","Tell the real story at whatever level confidentiality allows — sanitized but true.","Acknowledge the cost honestly; two minutes is two minutes."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-gov-mid-01","level":"mid","profession":"publicservice","title":"The briefing note skeleton","scenario":"You owe the director a one-page briefing note on the rising misuse of the community grant program. You have fourteen observations in your notes — audit flags, anecdotes, two policy gaps, staffing pressure. A note that lists all fourteen will die unread.","task":"Write the governing sentence plus the three section headers that would carry the note.","tips":["One governing idea: what should the director conclude from all fourteen points?","Group everything under at most three buckets — points that fit nowhere may not belong.","Each header states a claim, not a topic: 'Controls lag the program's growth,' not 'Background.'"],"focus":["structure","clarity"],"placeholder":"Governing idea: the grant program has outgrown its controls. Three sections:"},
    {"id":"structure-gov-mid-02","level":"mid","profession":"publicservice","title":"SCQA for the budget ask","scenario":"You're requesting $60K to replace the unit's aging inspection vehicles. Before the numbers, the request needs a frame: what's stable, what changed, what question that raises, and your answer. You have the parts scattered across three old emails.","task":"Write the four SCQA sentences for the vehicle request.","tips":["Situation: the fleet has served reliably — one sentence of stable context.","Complication: what broke the stability — repair costs doubled, two vehicles failed inspection.","Question flows naturally ('replace or keep repairing?'); Answer is your ask with the number."],"focus":["structure","impact"],"placeholder":"S: Our five inspection vehicles have run since 2016. C: This year, repair costs —"},
    {"id":"structure-gov-mid-03","level":"mid","profession":"publicservice","title":"PREP at the community mic","scenario":"At tonight's community meeting someone will ask why the new shelter site was chosen over the alternative on the west side. You'll answer aloud, unscripted, in front of a skeptical room. PREP — point, reason, example, point — keeps a spoken answer from wandering.","task":"Say a PREP-structured answer of 4-5 sentences to the site question.","tips":["Point first: the site was chosen because it meets the access criteria the west site couldn't.","One reason, one concrete example — transit access, distance to services.","Restate the point in different words to land the close."],"focus":["structure","clarity"]},
    {"id":"structure-gov-mid-04","level":"mid","profession":"publicservice","title":"Grouping the complaint pile","scenario":"Thirty-one complaints came in about the new parking enforcement rollout. Reading them raw, they blur together. Before your report to the director, they need shape: you can see signage confusion, payment-app failures, and enforcement timing disputes hiding in the pile.","task":"Write a 3-4 sentence summary that groups the 31 complaints into named themes with rough counts.","tips":["Name each theme by its cause, not its emotion: 'signage confusion,' not 'anger.'","Rough counts per theme show where the fix effort goes.","A reader should retain three themes; they will not retain 31 complaints."],"focus":["structure","precision"],"placeholder":"The 31 complaints fall into three groups: signage confusion (14), payment-app failures (11), and —"},
    {"id":"structure-gov-mid-05","level":"mid","profession":"publicservice","title":"The debrief that goes somewhere","scenario":"You're structuring the debrief document for last week's warming-centre activation. Raw notes mix praise, gaps, and war stories. The document needs to leave three things behind: what happened, what worked, and what changes before the next activation — with owners.","task":"Write the three section headers and one example line under each.","tips":["'What happened' is facts and timeline — no judgment yet.","'What worked' earns its place by naming things to protect, not just applause.","'What changes' is the only section anyone rereads: action, owner, date."],"focus":["structure","impact"]},
    {"id":"structure-gov-mid-06","level":"mid","profession":"publicservice","title":"The staffing proposal in three buckets","scenario":"Your case for converting two casual positions to permanent has a dozen supporting points: turnover costs, training waste, service continuity, recruitment data, a near-miss caused by an inexperienced casual. As a list it reads like venting.","task":"Group the case into three labeled arguments and write the one-sentence claim for each.","tips":["Candidate buckets: cost, service risk, evidence it works elsewhere.","Every point must serve a bucket's claim or get cut.","The three claims, read alone, should make the whole argument."],"focus":["structure","clarity"],"placeholder":"Claim 1 (cost): Churn in casual roles costs more than the conversion. Claim 2:"},
    {"id":"structure-gov-mid-07","level":"mid","profession":"publicservice","title":"The agenda that produces decisions","scenario":"You're chairing next week's four-agency coordination meeting on the transit-corridor response. The last meeting drifted for ninety minutes and decided nothing. The agenda is your structural tool: each item needs an outcome type and a time box.","task":"Write a 4-item agenda where each line names the item, the outcome needed (decide/input/inform), and minutes allotted.","tips":["Put the decision items first while attention is highest.","'Update' items go last or into the pre-read.","An item without a named outcome is a conversation, not an agenda item."],"focus":["structure","concision"],"placeholder":"1. Liaison coverage gaps — DECIDE backfill approach (15 min). 2."},
    {"id":"structure-gov-mid-08","level":"mid","profession":"publicservice","title":"The rollout in phases","scenario":"The new inspection scheduling process rolls out over six weeks: pilot crew first, then two districts, then everyone. Your announcement draft mixes the phases together and staff can't tell when it hits them.","task":"Write a 3-4 sentence announcement structured by phase, so each reader can find their date.","tips":["Structure by when-it-affects-you, not by project milestones.","One line per phase: who, what changes, from when.","Close with the one behavior that's the same for everyone."],"focus":["structure","audience"]},
    {"id":"structure-gov-mid-09","level":"mid","profession":"publicservice","title":"Twelve findings, three headlines","scenario":"The internal audit of your unit produced twelve findings, ranging from a missing signature protocol to real gaps in contractor oversight. Your response memo to the director can't march through all twelve serially — the serious ones would drown.","task":"Write a 2-3 sentence opening that groups the twelve findings by severity and names the theme of each group.","tips":["Severity is the reader's sorting need: what's serious, what's housekeeping.","Name the theme that links the serious ones — likely one root cause.","Signal the full list is appended; the memo carries the shape."],"focus":["structure","precision"],"placeholder":"Of the twelve findings, three are serious and share a root cause: contractor oversight."},
    {"id":"structure-gov-mid-10","level":"mid","profession":"publicservice","title":"The ops report template","scenario":"Your weekly report to the director has grown organically into a scroll of paragraphs. You're rebuilding it as a template: the same four sections every week, so the director always knows where to look and you always know what to write.","task":"Name the four standing sections in priority order and write the one-line purpose of each.","tips":["Order by what the director acts on: decisions needed, then risks, then results, then routine.","A standing 'Decisions needed' section — even when empty — trains the reader where to look.","If a section hasn't changed, one line says so; templates permit brevity."],"focus":["structure","concision"]},
    {"id":"structure-gov-mid-11","level":"mid","profession":"publicservice","title":"SCQA for the exception request","scenario":"You want the director to approve an exception to the procurement threshold so you can extend the current snow-clearing contractor for one season instead of re-tendering mid-winter. Cold, the request sounds like rule-dodging. Framed, it's obviously sensible.","task":"Write the four SCQA sentences for the exception request.","tips":["Situation: contracts are normally re-tendered on schedule — you respect the rule.","Complication: the tender timeline now lands the changeover in January.","The question frames itself: switch contractors mid-season or extend one season? Answer with your ask."],"focus":["structure","clarity"]},
    {"id":"structure-gov-mid-12","level":"mid","profession":"publicservice","title":"PREP for the wait-time question","scenario":"In the quarterly review, your director asks point-blank: 'Why are processing times up 30%?' You know the answer — a retirement, a system change, and a volume spike hit the same quarter — but spoken raw it sounds like three excuses.","task":"Say a PREP answer of 4-5 sentences that carries the three causes inside one point.","tips":["Point: times rose because capacity dropped exactly when volume spiked — recoverable by year-end.","The three causes are the Reason, delivered as one compound fact, not three apologies.","Close on the recovery plan, not the excuses."],"focus":["structure","impact"],"placeholder":"Processing times rose because we lost capacity in the same quarter volume spiked — and it's recoverable."},
    {"id":"structure-gov-mid-13","level":"mid","profession":"publicservice","title":"Shaping the consultation feedback","scenario":"The public consultation on the park redesign produced 340 comments. The summary you owe the project board can't be a comment dump — the board needs what the community converged on, where it split, and what surprised the team.","task":"Write a 3-4 sentence summary structured as: convergence, divergence, surprise.","tips":["Convergence first — it's the mandate the board can act on.","Divergence needs the fault line named: dog owners vs. families isn't 'mixed feedback.'","One genuine surprise proves you actually read the comments."],"focus":["structure","audience"],"placeholder":"The community converged on one priority: keep the mature trees. Opinion split on —"},
    {"id":"structure-gov-mid-14","level":"mid","profession":"publicservice","title":"The vendor memo, pyramid style","scenario":"Your evaluation panel scored three security-services bids and you're writing the award recommendation. The pyramid: recommendation on top, three supporting reasons, evidence under each. Your draft instead walks chronologically through the evaluation process.","task":"Write the top of the pyramid — the recommendation sentence and the three reason sentences.","tips":["Top line: recommend Vendor X at $Y — the decision the memo exists for.","Each reason is a claim the scores support: strongest coverage plan, best transition record, lowest total cost.","Process description proves fairness; it lives in an appendix, not the argument."],"focus":["structure","clarity"]},
    {"id":"structure-gov-mid-15","level":"mid","profession":"publicservice","title":"The shift briefing in priority order","scenario":"Tonight's briefing has seven items: a wanted-person alert, a road closure, two administrative reminders, a new form, an equipment note, and a commendation. Read in the order they arrived, the alert lands fourth and half the room has tuned out.","task":"Reorder the seven items into a priority structure and write the one-line rule you used.","tips":["Order by consequence-if-missed, not by when items reached your inbox.","Safety and live operational items first, always.","End on the commendation — structure can serve morale too."],"focus":["structure","clarity"],"placeholder":"Order: alert, road closure, new form, equipment, admin x2, commendation. Rule:"},
    {"id":"structure-gov-mid-16","level":"mid","profession":"publicservice","title":"The grant narrative's spine","scenario":"You're writing your program's application for provincial renewal funding. You have outcomes data, testimonials, partnership letters, and cost figures. Without a governing idea, it reads as a scrapbook. With one, everything becomes evidence for a single claim.","task":"Write the governing sentence of the application and name which three evidence groups support it.","tips":["The governing idea is a claim about impact per dollar, not a description of activities.","Sort every asset under one of three proofs; orphan assets get cut.","Funders remember one sentence — write the one you want remembered."],"focus":["structure","impact"]},
    {"id":"structure-gov-mid-17","level":"mid","profession":"publicservice","title":"The acting-supervisor handover","scenario":"You're away for three weeks and a senior team member is acting in your place. Your handover draft is a brain-dump of forty items. The acting supervisor needs a structure: what to decide alone, what to escalate, what can simply wait for you.","task":"Write the three handover sections as headers with one example item under each.","tips":["The decide/escalate/wait split is the whole gift — it removes forty judgment calls.","Under 'escalate,' name the person and the trigger, not just the topic.","Anything in 'wait' truly waits; resist promoting items out of anxiety."],"focus":["structure","clarity"],"placeholder":"Decide yourself: routine scheduling, leave under 3 days. Escalate to the director if:"},
    {"id":"structure-gov-mid-18","level":"mid","profession":"publicservice","title":"The investigation summary","scenario":"You've finished investigating a resident's complaint that a crew damaged their fence and denied it. Your summary for the file must hold up if the complaint escalates: allegation, evidence gathered, finding, and action — cleanly separated, never blended.","task":"Write the four-part summary in 4-6 sentences with each part clearly delimited.","tips":["State the allegation in the complainant's terms, uncolored.","Evidence is what you found, not what you concluded — keep the wall between them.","The finding sentence starts 'On the evidence, I find —' and the action follows with a date."],"focus":["structure","precision"]},
    {"id":"structure-gov-mid-19","level":"mid","profession":"publicservice","title":"The Q&A prep doc","scenario":"Your director faces the committee next week on your program's overspend and you're building the Q&A binder. Twenty possible questions, currently in random order. Grouped well, the director preps three arguments; grouped badly, twenty separate answers.","task":"Sort the questions into three named groups and write the headline answer for one group.","tips":["Group by the answer they share, not by topic: all 'why did costs rise' variants take one answer.","Name the hostile group honestly — 'accountability questions' — and give it the strongest answer.","Each group's headline answer should survive being the only thing remembered."],"focus":["structure","audience"]},
    {"id":"structure-gov-mid-20","level":"mid","profession":"publicservice","title":"Three asks, none lost","scenario":"Your email to the facilities manager carries three unrelated asks: a repair quote by Friday, access badges for two new staff, and a date for the annual fire inspection. Drafted as one paragraph, at least one ask will be missed — probably the one you need most.","task":"Restructure the email so all three asks survive: write the opening line and the three-item structure.","tips":["Opening line announces the count: 'Three requests, in priority order.'","One numbered line per ask, each with its own deadline.","Never bury an ask in the middle of a paragraph about a different ask."],"focus":["structure","concision"],"placeholder":"Three requests, in priority order: 1. Repair quote for the loading door by Friday. 2."},
    {"id":"structure-gov-mid-21","level":"mid","profession":"publicservice","title":"The training session outline","scenario":"You're delivering a 45-minute session on the new incident-reporting procedure. Your slides currently follow the policy document's structure — definitions, scope, procedure, appendices. Adults learn from need-to-act structure: what changed, how to do it, practice, questions.","task":"Write the four-block outline with minutes per block and the goal of each.","tips":["Structure by the learner's job, not the document's chapters.","The practice block is where learning happens — protect its minutes.","Open with why the change protects them; motivation buys attention."],"focus":["structure","audience"]},
    {"id":"structure-gov-mid-22","level":"mid","profession":"publicservice","title":"The after-action skeleton","scenario":"The flood-response after-action report is yours to draft, and three agencies will read it looking for blame. A tight structure keeps it useful and fair: scope, timeline of key decisions, findings tied to evidence, recommendations tied to findings.","task":"Write the section headers plus a one-line rule for what each section may and may not contain.","tips":["The timeline records decisions and information available at the time — hindsight stays out.","Every finding cites evidence; every recommendation cites a finding. No orphans in either direction.","A 'contributing conditions' section beats a 'failures' section for keeping three agencies at the table."],"focus":["structure","precision"]},
    {"id":"structure-gov-mid-23","level":"mid","profession":"publicservice","title":"The options paper with criteria","scenario":"The director asked for options on the aging community centre: renovate, rebuild, or consolidate with the north site. An options paper without explicit criteria invites the reader to relitigate everything. Criteria first, then options scored against them.","task":"Write the opening 2-3 sentences that establish the three decision criteria before any option appears.","tips":["Criteria come from the decision-maker's world: cost ceiling, service continuity, timeline.","Get the criteria agreed and the recommendation almost argues itself.","Score every option against every criterion — gaps read as thumb-on-scale."],"focus":["structure","clarity"],"placeholder":"Three criteria frame this decision: total cost within the capital envelope, no service gap longer than —"},
    {"id":"structure-gov-mid-24","level":"mid","profession":"publicservice","title":"From meeting chaos to record","scenario":"Your notes from the program review meeting are two pages of fragments: decisions, half-decisions, complaints, and action items tangled together. The record you circulate needs three clean lists — decided, actions with owners, and parked — and nothing else.","task":"Write the three-list structure with one realistic example entry in each list.","tips":["A decision entry states what was decided, by whom, effective when.","An action without an owner and date is a wish — upgrade it or park it.","The parking lot is honorable; it's where half-decisions go instead of haunting the record."],"focus":["structure","concision"],"placeholder":"DECIDED: Intake moves to the online form effective Sept 1 (approved by J. Marsh). ACTIONS:"},
    {"id":"structure-gov-mid-25","level":"mid","profession":"publicservice","title":"One idea per paragraph","scenario":"Your draft memo on the volunteer program's future has paragraphs doing triple duty — one starts with recruitment numbers, drifts into a budget concern, and ends on a training anecdote. Readers finish each paragraph unsure what it claimed.","task":"Rewrite one such paragraph as 2-3 paragraphs, each opening with its own claim sentence.","tips":["Test each paragraph: can you title it in five words? If two titles fit, split it.","The first sentence of each paragraph is its claim; everything after supports only that.","Drifting paragraphs usually hide the writer's own undecided thinking — deciding is the fix."],"focus":["structure","clarity"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-gov-mid-01","level":"mid","profession":"publicservice","title":"Halve the all-staff email","scenario":"Your draft announcing the summer parking arrangements runs 220 words: a warm preamble, the change, three contingencies, a restatement of the change, and a closing paragraph thanking everyone for flexibility. The content is one change and one date.","task":"Rewrite the email at half the length without losing any real information.","tips":["Cut the preamble and the thank-you paragraph first — they carry zero content.","State the change once; restatement is a sign you didn't trust the first statement.","Contingencies collapse to one line: 'If X, do Y.'"],"focus":["concision","clarity"]},
    {"id":"concise-gov-mid-02","level":"mid","profession":"publicservice","title":"The hedge-free recommendation","scenario":"Your memo to the director recommends ending the underused evening service. The draft says: 'It would perhaps be worth considering whether the evening service might potentially be a candidate for review.' Five hedges deep, the recommendation has vanished.","task":"Rewrite the recommendation sentence with at most one justified qualifier.","tips":["'Perhaps,' 'consider whether,' 'might potentially,' 'candidate for review' — stack them and you've said nothing.","Keep the one qualifier that carries information; delete the ones that carry fear.","If you truly recommend it, the sentence starts 'I recommend.'"],"focus":["concision","impact"],"placeholder":"I recommend ending the evening service in September."},
    {"id":"concise-gov-mid-03","level":"mid","profession":"publicservice","title":"Kill the meta-commentary","scenario":"Your briefing note opens: 'The purpose of this note is to provide an overview of the current situation regarding the shelter capacity issue and to outline potential considerations going forward.' Thirty words about the note, zero about shelters.","task":"Replace the meta-opening with a first sentence that delivers actual content.","tips":["A note never needs to announce its purpose — its first sentence should perform it.","'Outline potential considerations going forward' is filler wearing a suit.","Start with the fact or the recommendation the note exists for."],"focus":["concision","clarity"],"placeholder":"Shelter capacity will fall 40 beds short this winter unless —"},
    {"id":"concise-gov-mid-04","level":"mid","profession":"publicservice","title":"De-nominalize the policy memo","scenario":"Your draft is thick with nominalizations: 'undertake an assessment of,' 'conduct a review of,' 'make a determination regarding,' 'provide notification to.' Each one hides a verb inside a noun and adds three words of dead weight.","task":"Rewrite these four phrases as plain verbs inside one 2-sentence passage.","tips":["'Undertake an assessment of' = assess. 'Make a determination regarding' = decide.","Nominalizations feel official; they read as evasive.","The actor returns when the verb does: 'we will assess,' not 'an assessment will be undertaken.'"],"focus":["concision","clarity"],"placeholder":"We will assess the site, review the contract, decide on renewal, and notify the vendor by —"},
    {"id":"concise-gov-mid-05","level":"mid","profession":"publicservice","title":"The redundant-pair purge","scenario":"The SOP you're revising is full of legal-sounding doubles: 'each and every staff member,' 'full and complete records,' 'null and void,' 'first and foremost.' They add rhythm and nothing else, and this SOP needs to fit on two pages.","task":"Rewrite a 3-sentence SOP passage removing every redundant pair.","tips":["Pick one word from each pair; the meaning never changes.","Doubles survive from legal drafting traditions that don't apply to an SOP.","Every word cut from a procedure is a word staff can't misread."],"focus":["concision","precision"]},
    {"id":"concise-gov-mid-06","level":"mid","profession":"publicservice","title":"The incident narrative diet","scenario":"A staff member's incident report runs 400 words to describe a two-minute event: a visitor became agitated at the counter and left when asked. Every sentence is padded — 'at that point in time,' 'proceeded to approach,' 'in the vicinity of.'","task":"Rewrite the core narrative in under 100 words, keeping every fact.","tips":["'Proceeded to approach' is 'approached.' 'At that point in time' is 'then' — or nothing.","Facts, times, and exact words spoken survive; padding doesn't.","Short reports get read; that's their protection value."],"focus":["concision","precision"]},
    {"id":"concise-gov-mid-07","level":"mid","profession":"publicservice","title":"Bureaucratese to plain notice","scenario":"The draft public notice reads: 'Please be advised that, effective as of the date first written above, the facility's operational hours will be subject to modification in accordance with the revised seasonal schedule.' Nobody outside the building talks like this.","task":"Rewrite the notice in one plain sentence a resident absorbs at a glance.","tips":["'Please be advised that' has never advised anyone — delete on sight.","Name the actual hours and the actual date; 'subject to modification' hides both.","Read it aloud: if you wouldn't say it to a neighbour, don't post it."],"focus":["concision","audience"],"placeholder":"Starting July 1, the centre is open 8 a.m. to 6 p.m. weekdays."},
    {"id":"concise-gov-mid-08","level":"mid","profession":"publicservice","title":"The 30-second voicemail","scenario":"You need to leave your director a voicemail: the ministry inspection moved up to Tuesday, you'll have the file ready, and you need their sign-off on one item by Monday noon. Your rehearsal version rambles for ninety seconds.","task":"Script the voicemail in 3 sentences deliverable in under 30 seconds.","tips":["Name, topic, ask — then stop.","One item per breath: inspection moved, file ready, need sign-off Monday noon.","A voicemail is a headline, not a meeting."],"focus":["concision","clarity"],"placeholder":"It's Sam — the ministry inspection moved up to Tuesday. File will be ready; I need your sign-off on the staffing annex by Monday noon."},
    {"id":"concise-gov-mid-09","level":"mid","profession":"publicservice","title":"Cut the throat-clearing","scenario":"You open team meetings with two minutes of ritual: thanks for coming, acknowledgment of how busy everyone is, a weather remark, an apology for the meeting itself. The team's attention — highest in the first minute — is spent on nothing.","task":"Write the first two sentences of a meeting opening that starts on substance.","tips":["The first sentence names the meeting's one job.","Warmth can live inside substance: 'Good news first —' is warm and moving.","Apologizing for a meeting you called tells the room it's optional."],"focus":["concision","impact"],"placeholder":"We're here to settle the fall schedule — two decisions, twenty minutes."},
    {"id":"concise-gov-mid-10","level":"mid","profession":"publicservice","title":"The weekly report, condensed","scenario":"Your weekly report has swollen to 900 words because every section carries over boilerplate from the week before. The director admitted they skim it. What changed this week fits in 200 words; the rest is furniture.","task":"Rewrite this week's report at 200 words: only what changed, decided, or needs attention.","tips":["'No change' is a complete and honest section.","Boilerplate context belongs in a linked reference doc, not repeated weekly.","A report the director actually reads beats a thorough one they skim."],"focus":["concision","structure"]},
    {"id":"concise-gov-mid-11","level":"mid","profession":"publicservice","title":"The one-line answer","scenario":"The director's assistant emails: 'Can the director tell the committee the pilot ends March 31?' The answer is yes. You've drafted three paragraphs of pilot history, evaluation methodology, and caveats that don't change the answer.","task":"Write the reply in one sentence.","tips":["When the answer is yes and the caveats don't change it, the answer is 'Yes.'","Unrequested detail delays the reader and dilutes your reliability.","Offer depth as an option: 'Happy to brief further if useful.'"],"focus":["concision","clarity"],"placeholder":"Yes — the pilot ends March 31, confirmed."},
    {"id":"concise-gov-mid-12","level":"mid","profession":"publicservice","title":"Trim the complaint response","scenario":"Your draft reply to a service complaint runs 350 words. Half is institutional self-description — 'we strive to,' 'our commitment to excellence,' 'we take all feedback seriously.' The resident wants three things: what happened, what you're doing, when it's fixed.","task":"Rewrite the reply at under 150 words covering exactly those three things.","tips":["Every 'we strive' sentence is a sentence the resident skips to find the answer.","One apology, specific to what actually went wrong.","End with the date and a name — accountability is the best closer."],"focus":["concision","audience"]},
    {"id":"concise-gov-mid-13","level":"mid","profession":"publicservice","title":"The unpadded no","scenario":"A staff member asked to swap onto day shifts for six weeks. You can't accommodate it — coverage doesn't allow it. Your draft spends four sentences apologizing before and after a 'no' so buried it reads like a maybe.","task":"Write the decline in 2-3 sentences: clear no, one reason, one alternative if real.","tips":["A padded no gets re-asked; a clear no gets respected.","One honest reason beats four cushions.","Offer an alternative only if you mean it — 'revisit in September' must be real."],"focus":["concision","clarity"],"placeholder":"I can't approve the swap — we can't cover nights for six weeks. What I can do:"},
    {"id":"concise-gov-mid-14","level":"mid","profession":"publicservice","title":"The slide that stopped being a document","scenario":"Your briefing slide for the ops review has 11 bullet points, three sub-bullets each, in 14-point text. You will read it to the room, which is what slides this dense force. It needs to become a visual aid for a spoken point.","task":"Rewrite the slide as a headline plus at most three bullets, and note what moves to your talk track.","tips":["The slide headline states the takeaway, not the topic.","If you'll say it aloud, it doesn't need to be on the slide too.","Detail the room might ask for goes in an appendix slide, not slide one."],"focus":["concision","structure"]},
    {"id":"concise-gov-mid-15","level":"mid","profession":"publicservice","title":"The job posting paragraph","scenario":"The posting for your vacant coordinator role opens with 95 words of departmental self-description before mentioning the job. Strong candidates skim postings the way you skim resumes — the first lines must sell the role, not the org chart.","task":"Rewrite the opening at 40 words or fewer, leading with what the person will do and why it matters.","tips":["Lead with the work: 'You'll run intake for 2,000 families a year.'","The department's history survives fine in the last paragraph.","Concrete verbs attract doers; abstractions attract nobody."],"focus":["concision","audience"],"placeholder":"You'll coordinate emergency housing intake for 2,000 families a year —"},
    {"id":"concise-gov-mid-16","level":"mid","profession":"publicservice","title":"The stock-phrase sweep","scenario":"You're editing a colleague's draft letter before it goes out under your unit's name. It's carpeted with government stock phrases: 'as per our conversation,' 'please be advised,' 'at this time,' 'moving forward,' 'in due course.' Each is removable or replaceable with something shorter and warmer.","task":"Rewrite a 3-sentence passage eliminating every stock phrase.","tips":["'As per our conversation' = 'as we discussed' — or often nothing.","'At this time' and 'moving forward' are pure filler; 'in due course' means 'we won't commit to a date' — commit to one instead.","Stock phrases signal a form letter; plain phrases signal a person."],"focus":["concision","audience"]},
    {"id":"concise-gov-mid-17","level":"mid","profession":"publicservice","title":"The pager-length alert","scenario":"The duty system sends alerts capped at 160 characters. You need on-call staff to know: flooding at the Hillside underpass, road closed, crews dispatched, next update at 9 p.m. Your draft is 300 characters.","task":"Write the alert in under 160 characters without losing an essential fact.","tips":["Telegraphic grammar is correct grammar for an alert.","Location, status, action, next update — in that order.","Cut adjectives first; 'significant flooding' floods no differently than 'flooding.'"],"focus":["concision","precision"],"placeholder":"Hillside underpass flooded, road closed. Crews on site. Next update 2100."},
    {"id":"concise-gov-mid-18","level":"mid","profession":"publicservice","title":"The deficiency notice, tightened","scenario":"Your draft notice to the cleaning contractor lists deficiencies inside long narrative sentences: 'It was observed during the inspection of June 12 that washroom facilities on the second floor had not been serviced in accordance with the standards set out in...' Each item needs to be findable and checkable.","task":"Rewrite three deficiencies as a tight numbered list with location, issue, and required-by date.","tips":["'It was observed that' precedes every item — delete it everywhere.","One line per deficiency: where, what, fix-by date.","A checkable list gets fixed; a narrative gets a reply letter."],"focus":["concision","precision"],"placeholder":"1. 2nd-floor washrooms: not serviced June 10-12. Rectify by June 20."},
    {"id":"concise-gov-mid-19","level":"mid","profession":"publicservice","title":"Three paragraphs to three bullets","scenario":"Your FYI email to peer supervisors about the fleet-booking change runs three paragraphs. Reading it back, each paragraph contains exactly one fact wrapped in context they already have: the system, the date, the exception.","task":"Convert the email to a one-line opener plus three bullets.","tips":["When each paragraph hides one fact, the format is a list.","Peers share your context — write for what they don't know.","An FYI should cost the reader fifteen seconds."],"focus":["concision","structure"],"placeholder":"Fleet booking changes Monday — three things: • New bookings go through —"},
    {"id":"concise-gov-mid-20","level":"mid","profession":"publicservice","title":"Halve the talking points","scenario":"You have a two-minute slot at the directors' meeting to report on the outreach program. Your talking points run to five minutes of material. Cutting isn't trimming words — it's choosing which two of six points survive.","task":"Pick the two points that survive and write them as spoken lines; name what you cut.","tips":["Survivors are chosen by what the directors can act on, not what you worked hardest on.","Two points landed beats six points blurred.","The cut material isn't lost — it's your Q&A ammunition."],"focus":["concision","impact"]},
    {"id":"concise-gov-mid-21","level":"mid","profession":"publicservice","title":"The thread reply that repeats nothing","scenario":"You're the sixth reply in an email thread about the venue for the public hearing. Your draft restates the whole saga — the double-booking, the accessibility issue, the two candidate rooms — before adding your actual contribution: Room B works and you've held it.","task":"Write a reply of 1-2 sentences that adds only what's new.","tips":["The thread already contains the thread — never re-narrate it.","Your contribution is two facts: Room B confirmed, held until Friday.","Late-thread replies earn reads by being short."],"focus":["concision","clarity"],"placeholder":"Room B works — I've placed a hold until Friday."},
    {"id":"concise-gov-mid-22","level":"mid","profession":"publicservice","title":"The SOP step diet","scenario":"Step 4 of the cash-handling SOP reads: 'The staff member responsible for the reconciliation process should then proceed to verify that the amounts recorded in the daily log are consistent with the physical cash count that was previously conducted.' That's one instruction in 38 words.","task":"Rewrite the step in ten words or fewer without losing the instruction.","tips":["SOP steps are commands: verb first, one action each.","'Should then proceed to verify' is 'verify.'","If a step needs 38 words, it's probably two steps."],"focus":["concision","precision"],"placeholder":"Verify the daily log matches the cash count."},
    {"id":"concise-gov-mid-23","level":"mid","profession":"publicservice","title":"Active voice for the incident summary","scenario":"The incident summary you're finalizing says: 'It was determined that the gate had been left unsecured and notification was not provided to the on-duty supervisor.' The passive voice has quietly deleted every actor from a report whose whole job is accountability.","task":"Rewrite the sentence in active voice with the actors restored.","tips":["Every passive verb hides a who — restore each one.","'Notification was not provided' becomes 'the contractor did not notify' — different sentence, same facts.","Accountability documents need actors; passives read as protection."],"focus":["concision","precision"],"placeholder":"The night contractor left the gate unsecured and did not notify the on-duty supervisor."},
    {"id":"concise-gov-mid-24","level":"mid","profession":"publicservice","title":"Minutes that fit one page","scenario":"Your last coordination-meeting minutes ran four pages because they transcribed the discussion. Nobody read them. Minutes have one job: record decisions, actions, and owners — the discussion evaporates, and that's fine.","task":"Write one-page-style minutes for a meeting: 2-3 decisions and 2-3 actions, one line each.","tips":["'Discussion ensued' summarizes every discussion ever — decisions are what happened.","Each action line: verb, owner, date. Nothing else qualifies.","If someone wants the debate preserved, that's a different document they should write."],"focus":["concision","structure"]},
    {"id":"concise-gov-mid-25","level":"mid","profession":"publicservice","title":"The four-sentence executive summary","scenario":"Your ten-page review of the neighbourhood grants program is done. The executive summary is the only part the deputy director will read, and your draft summary is a page long — a summary that itself needs summarizing.","task":"Write the executive summary in four sentences: finding, evidence, recommendation, cost.","tips":["One sentence per job: what you found, the key number behind it, what to do, what it costs.","If a sentence doesn't change what the deputy knows or decides, it's not executive.","Write the summary last, cut it hardest."],"focus":["concision","impact"],"placeholder":"The grants program reaches half the neighbourhoods it funds."}
  ],
  "precision-and-evidence": [
    {"id":"precision-gov-mid-01","level":"mid","profession":"publicservice","title":"'Significant increase' in the quarterly report","scenario":"Your quarterly report to the director says service requests saw 'a significant increase.' The actual number: requests rose from 1,240 to 1,690 — 36% — while staffing stayed flat. 'Significant' makes the director ask; the number lets them act.","task":"Rewrite the sentence with the figures and the one comparison that gives them meaning.","tips":["Replace the intensifier with the two numbers and the percentage.","Add the comparison that carries the so-what: staffing unchanged.","A director quotes numbers upward; nobody quotes 'significant.'"],"focus":["precision","impact"],"placeholder":"Service requests rose 36% this quarter — 1,240 to 1,690 — on unchanged staffing."},
    {"id":"precision-gov-mid-02","level":"mid","profession":"publicservice","title":"'Soon' in the public notice","scenario":"The draft notice about the playground repair says work will be completed 'soon' and the area will reopen 'shortly thereafter.' The contractor's schedule says work ends August 8 and inspection clears it within five business days. Residents call the office every day 'soon' stays on the sign.","task":"Rewrite the notice line with dates or bounded ranges instead of the vague timeframes.","tips":["'Soon' becomes a date; 'shortly thereafter' becomes 'within five business days of completion.'","If a date could slip, give the range you'd defend, not a word that promises nothing.","Every vague timeframe on a public notice converts directly into phone calls."],"focus":["precision","audience"],"placeholder":"Repairs finish August 8; the playground reopens by August 15."},
    {"id":"precision-gov-mid-03","level":"mid","profession":"publicservice","title":"'Several complaints' becomes a count","scenario":"Your memo flags 'several complaints' about the new enforcement officer. The file shows exactly four complaints in six weeks — two about tone, two about a misapplied bylaw section — against a unit average of one per officer per quarter. 'Several' hides both the size and the pattern.","task":"Rewrite the flag with the count, the timeframe, and the baseline that makes it meaningful.","tips":["Count them: four in six weeks.","The baseline is the evidence — one per quarter is normal, four in six weeks is not.","Name the pattern inside the count: two tone, two misapplication."],"focus":["precision","clarity"],"placeholder":"Four complaints in six weeks — two about tone, two about a misapplied section — against a unit average of one per officer per quarter."},
    {"id":"precision-gov-mid-04","level":"mid","profession":"publicservice","title":"The overtime claim, audit-ready","scenario":"You're justifying the overtime spend to finance and your draft says the unit 'has been stretched thin due to unprecedented demand.' Finance will test every word. What you can prove: three vacancies since March, call volume up 22%, and every overtime shift tied to a minimum-staffing rule.","task":"Rewrite the justification as three checkable claims a skeptical analyst would accept.","tips":["'Stretched thin' is a feeling; three vacancies since March is a fact.","Tie the spend to a rule they can verify: minimum staffing levels.","Write as if every sentence will be tested against a record — because it will."],"focus":["precision","structure"],"placeholder":"Every overtime hour traces to the minimum-staffing rule: three positions vacant since March while call volume rose 22%."},
    {"id":"precision-gov-mid-05","level":"mid","profession":"publicservice","title":"'Understaffed' with the establishment math","scenario":"Your staffing memo opens: 'The unit is chronically understaffed.' The director has heard that from every unit. Your math is stronger than the adjective: establishment is 14, you're running 10, and two of those are on modified duties — effective strength 8.6 FTE against a workload built for 14.","task":"Rewrite the opening with the establishment-versus-actual numbers doing the arguing.","tips":["Establishment, actual, effective — three numbers tell the whole story.","'Chronically' invites debate; '10 of 14, two on modified duties' ends it.","Let the gap speak; adjectives on top of numbers weaken both."],"focus":["precision","impact"],"placeholder":"We are staffed at 10 of an establishment of 14, and with two members on modified duties, effective strength is 8.6 FTE."},
    {"id":"precision-gov-mid-06","level":"mid","profession":"publicservice","title":"The response-time claim a councillor can test","scenario":"A councillor asked whether response times in their ward are 'worse than the rest of the city.' Your data: ward median is 6.2 days against a citywide 5.1, driven almost entirely by one request type. Your draft answer says times are 'broadly comparable.' It will not survive their own FOI request.","task":"Write a 2-3 sentence answer with the real numbers and the driver, phrased for the councillor.","tips":["Give both medians — theirs and the city's — before any characterization.","Name the driver: one request type accounts for the gap.","An answer that survives their own data pull builds a year of trust."],"focus":["precision","audience"],"placeholder":"Your ward's median is 6.2 days against 5.1 citywide. The gap comes almost entirely from —"},
    {"id":"precision-gov-mid-07","level":"mid","profession":"publicservice","title":"The data point that needs a so-what","scenario":"Your briefing note states: 'Shelter turn-aways totaled 412 this quarter.' True — and the director doesn't know if that's a crisis or a Tuesday. Your analysis: it's up 18% year over year, concentrated on weekend nights, and fixable with one staffed overflow room.","task":"Rewrite the line as number plus insight plus implication, in two sentences.","tips":["A number without a comparison is trivia; add the year-over-year.","The pattern is the insight: weekend nights, not everywhere.","End on what the number asks the director to do."],"focus":["precision","impact"],"placeholder":"Turn-aways hit 412 this quarter, up 18% year over year and concentrated on weekend nights — a gap one staffed overflow room would close."},
    {"id":"precision-gov-mid-08","level":"mid","profession":"publicservice","title":"'The program is working' — prove it","scenario":"Your renewal memo for the youth diversion program says it 'has been highly successful.' The evaluation data: 84 participants, 71 completed, and a 12-month reoffence rate of 9% against 31% for the comparison group. The adjective is doing work the numbers do better.","task":"Rewrite the claim as evidence a skeptical funder would accept.","tips":["Completion and outcome numbers, with the comparison group — that's the proof.","'Highly successful' invites the question; 9% versus 31% answers it.","One honest caveat about sample size buys credibility for everything else."],"focus":["precision","impact"],"placeholder":"Of 84 participants, 71 completed, and their 12-month reoffence rate was 9% against 31% for the comparison group."},
    {"id":"precision-gov-mid-09","level":"mid","profession":"publicservice","title":"'Aging fleet' with a maintenance ledger","scenario":"Your capital request describes 'an aging fleet requiring increasing maintenance.' The ledger says it better: average vehicle age 11 years against a 7-year lifecycle, repair costs up from $28K to $61K in two years, and two units out of service more days than in.","task":"Rewrite the description with the three figures that make the case unanswerable.","tips":["Age against lifecycle standard is the anchor comparison.","The cost trend — $28K to $61K — is the argument in one line.","'Two units out of service more days than in' is a number wearing a story."],"focus":["precision","concision"],"placeholder":"The fleet averages 11 years against a 7-year lifecycle; repairs rose from $28K to $61K in two years."},
    {"id":"precision-gov-mid-10","level":"mid","profession":"publicservice","title":"'Agitated' in the incident report","scenario":"You're reviewing a staff member's incident report that describes a visitor as 'agitated and aggressive.' If this file ends up before a review board, those adjectives are opinions. What was observable: raised voice, struck the counter twice with an open hand, refused three requests to step back.","task":"Rewrite the description using only observable behavior a third party could verify.","tips":["Adjectives characterize; behaviors happened. Boards trust the second.","Count what can be counted: struck the counter twice, refused three requests.","Record the exact words spoken where they matter — quotes outrank summaries."],"focus":["precision","clarity"],"placeholder":"The visitor raised his voice, struck the counter twice with an open hand, and refused three requests to step back."},
    {"id":"precision-gov-mid-11","level":"mid","profession":"publicservice","title":"'Most residents support it' — says who?","scenario":"Your consultation summary claims 'most residents support the redesign.' The actual basis: 62% of 340 written comments were favourable — from a neighbourhood of 6,000. Stated carelessly, one hostile question at council turns your summary into an ambush.","task":"Rewrite the claim with the number, the base, and its honest limits.","tips":["62% of 340 comments is a real finding; 'most residents' is a claim you can't defend.","Name the base and the gap: comments received, not residents polled.","Precision about limits is armour, not weakness."],"focus":["precision","audience"],"placeholder":"Of 340 written comments, 62% favoured the redesign — a strong signal, though not a poll of the full neighbourhood."},
    {"id":"precision-gov-mid-12","level":"mid","profession":"publicservice","title":"The timeline you'd bet on","scenario":"The director asks when the records digitization finishes. Your draft says 'in the coming months.' Your honest estimate: October if the scanning vendor holds schedule, December if they slip like last time. A bounded range with its driver beats both false precision and mush.","task":"Write the timeline as a bounded range with the one variable that moves it.","tips":["Give both ends: October best case, December if the vendor slips.","Name what moves the needle so the range reads as knowledge, not hedging.","'Coming months' postpones this question; a range answers it once."],"focus":["precision","clarity"],"placeholder":"October if the vendor holds schedule; December if they slip as they did in phase one. I'll know which by August 15."},
    {"id":"precision-gov-mid-13","level":"mid","profession":"publicservice","title":"'High risk' on the risk register","scenario":"Your risk register entry for the aging pool mechanical system just says 'HIGH.' The deputy signing the capital plan needs what high means: a 40-year-old system, two failures last summer, and a failure in July closes the facility for an estimated six weeks in peak season.","task":"Rewrite the entry as likelihood and consequence in concrete terms, 2 sentences.","tips":["Likelihood: the failure history and age, not a colour code.","Consequence: six weeks closed, in July, quantified in visits if you have it.","A register entry should let a stranger re-derive your rating."],"focus":["precision","structure"],"placeholder":"Likelihood: the system is 40 years old and failed twice last summer. Consequence: a peak-season failure closes the pool an estimated six weeks."},
    {"id":"precision-gov-mid-14","level":"mid","profession":"publicservice","title":"The performance file in observables","scenario":"You're documenting a performance concern and your draft says the employee 'has a poor attitude and is unreliable.' HR will hand that back. The record: late for shift 6 times in 8 weeks, two missed report deadlines, and a documented refusal of a lawful task assignment on May 12.","task":"Rewrite the concern as dated, observable, checkable entries.","tips":["'Unreliable' is a conclusion; six lates in eight weeks is a record.","Date everything — undated observations read as impressions.","Write what a grievance arbitrator would accept, because one might."],"focus":["precision","structure"],"placeholder":"Between April 1 and May 26: late for shift 6 times, two report deadlines missed, and on May 12 a documented refusal of an assigned task."},
    {"id":"precision-gov-mid-15","level":"mid","profession":"publicservice","title":"The percentage with no base","scenario":"Your update reports 'a 40% increase in online applications.' The director forwards it upward and gets the obvious reply: 40% of what? The base was 55 applications a month, now 77 — real progress, but a very different picture than the naked percentage implied.","task":"Rewrite the line with the base numbers alongside the percentage.","tips":["A percentage without its base is a decoration, not a fact.","Small bases make big percentages — show both and stay honest.","Give the absolute number that matters operationally: 22 more a month."],"focus":["precision","clarity"],"placeholder":"Online applications rose 40% — from 55 to 77 a month — since the form redesign."},
    {"id":"precision-gov-mid-16","level":"mid","profession":"publicservice","title":"One story, one number","scenario":"Your funding pitch for the heat-response program has ten anecdotes and no data, because the stories feel powerful. They are — one at a time. The evaluation shows 1,900 wellness checks last summer and 14 medical escalations caught early. The pitch needs one story married to one number.","task":"Write a 2-3 sentence passage pairing the single best story with the single best number.","tips":["Ten anecdotes read as anecdotes; one anecdote plus a denominator reads as evidence.","Choose the story that is typical, not the most dramatic — credibility over theatre.","The number tells them it scales; the story tells them it matters."],"focus":["precision","impact"],"placeholder":"Last July a wellness check found Mr. Osei collapsed in a 38-degree apartment — one of 14 early medical catches among 1,900 checks."},
    {"id":"precision-gov-mid-17","level":"mid","profession":"publicservice","title":"The apples-to-apples comparison","scenario":"A peer supervisor claims your intake unit is 'twice as slow' as theirs. Their unit handles renewals; yours handles first applications, which require a document review theirs skip. Raw averages: theirs 3 days, yours 6.5 — but like-for-like renewals in your unit run 3.2 days.","task":"Write a 2-3 sentence correction that puts the comparison on a fair basis without sounding defensive.","tips":["Grant the raw numbers first — disputing true numbers kills you.","Then give the like-for-like figure that changes the conclusion.","State the basis difference in one clause, not a paragraph of grievance."],"focus":["precision","clarity"],"placeholder":"The raw averages are right — 3 days to our 6.5 — but they compare renewals to first applications. Like for like, our renewals run 3.2 days."},
    {"id":"precision-gov-mid-18","level":"mid","profession":"publicservice","title":"'Extensive outreach' itemized","scenario":"The consultation report you're finalizing says the team 'conducted extensive community outreach.' The record: 4 public sessions with 210 attendees, 2 pop-ups at the market, 340 written comments, and mailouts to 2,800 households. If it goes to council unquantified, one councillor will ask and the word will collapse.","task":"Rewrite the sentence as an itemized account in one or two sentences.","tips":["'Extensive' is a verdict — let the reader reach it from your inventory.","Four numbers in one sentence is fine when each is doing work.","Include reach (2,800 households), not just effort (2 pop-ups)."],"focus":["precision","concision"],"placeholder":"Outreach reached 2,800 households by mail and 210 residents across four public sessions, plus two market pop-ups and 340 written comments."},
    {"id":"precision-gov-mid-19","level":"mid","profession":"publicservice","title":"The budget variance, decomposed","scenario":"Your program is $47K over budget and your draft explanation says costs were 'higher than anticipated across several areas.' Finance needs the decomposition: $31K in overtime from two vacancies, $11K in emergency facility repairs, $5K in fuel. Vague variance explanations get line-by-line audits.","task":"Write a 2-sentence variance explanation with the three components and their causes.","tips":["Decompose to the dollar level you'd want to defend — three parts, three causes.","Order components by size; the $31K carries the explanation.","'Several areas' invites the audit that specificity prevents."],"focus":["precision","structure"],"placeholder":"The $47K variance is three items: $31K overtime from two unfilled positions, $11K emergency repairs at the depot, $5K fuel."},
    {"id":"precision-gov-mid-20","level":"mid","profession":"publicservice","title":"Report the number that hurts","scenario":"Your program update highlights that wait times fell 25%. It omits that abandoned applications rose 15% in the same period — probably because frustrated applicants gave up, which flatters the wait-time number. The director will eventually see both; only one order of discovery keeps your credibility.","task":"Write a 2-3 sentence update that presents both numbers and your honest read of the link.","tips":["Volunteer the counter-number before someone else finds it.","Name the possible connection plainly — hiding the inference is worse than the inference.","One report that cuts against you buys ten that don't get double-checked."],"focus":["precision","impact"],"placeholder":"Wait times fell 25% — but abandoned applications rose 15% in the same window, and the two may be connected."},
    {"id":"precision-gov-mid-21","level":"mid","profession":"publicservice","title":"'As soon as possible' in the tasking","scenario":"You're tasking a team member to prepare the inspection file 'as soon as possible.' To you that means Thursday, because the ministry arrives Monday. To them it means after their current queue. ASAP is a deadline that each reader sets for themselves.","task":"Rewrite the tasking with a date, a time, and the reason the date is real.","tips":["Replace ASAP with the actual deadline and the driver behind it.","Say what done looks like: reviewed, indexed, on your desk.","If everything is ASAP, nothing is — spend real dates carefully."],"focus":["precision","clarity"],"placeholder":"I need the inspection file reviewed and indexed on my desk by Thursday 3 p.m. — the ministry team arrives Monday."},
    {"id":"precision-gov-mid-22","level":"mid","profession":"publicservice","title":"'Inadequate' against a measurable standard","scenario":"Your facility inspection finding reads: 'Housekeeping in the food-preparation area was inadequate.' The operator will contest it. The standard is written: surfaces sanitized every 4 hours with logs kept; you found no log entries for 3 of the last 5 days and visible residue on two prep surfaces.","task":"Rewrite the finding as a measured gap against the named standard.","tips":["Cite the standard first, then the observed gap — findings argue by comparison.","No log entries for 3 of 5 days is uncontestable; 'inadequate' is a Tuesday of argument.","Precision in findings protects the inspector as much as it convicts the gap."],"focus":["precision","structure"],"placeholder":"Standard 4.2 requires sanitizing every 4 hours with logs. Logs show no entries for 3 of the last 5 days, and two prep surfaces had visible residue."},
    {"id":"precision-gov-mid-23","level":"mid","profession":"publicservice","title":"The grant report a funder can verify","scenario":"Your program's report to the provincial funder says you 'served many at-risk youth with positive outcomes.' The funder's analyst reconciles reports against intake data. Your real numbers: 132 enrolled, 118 with three or more sessions, 74% still in school at follow-up against 61% at intake.","task":"Rewrite the sentence with figures the analyst can match to your records.","tips":["Every claim should reconcile to a record the funder can request.","'Many' and 'positive' are the two words funding analysts distrust most.","The intake-to-follow-up comparison is your outcome — lead with it."],"focus":["precision","audience"],"placeholder":"We enrolled 132 youth, 118 of whom completed three or more sessions; school retention rose from 61% at intake to 74% at follow-up."},
    {"id":"precision-gov-mid-24","level":"mid","profession":"publicservice","title":"'Studies show' in the policy memo","scenario":"Your memo recommending the diversion-first approach says 'studies show this reduces reoffending.' Which studies? The two you actually rely on: a 2022 provincial evaluation (28% reduction over 24 months) and a national meta-analysis. Unsourced claims read as opinion in policy work.","task":"Rewrite the claim with the sources and the key figure named in the text.","tips":["Name the study, the year, and the number — in the sentence, not a footnote nobody reads.","One strong named source beats 'studies show' by a mile.","If a claim has no source you could name, it isn't ready for the memo."],"focus":["precision","impact"],"placeholder":"The 2022 provincial evaluation found diversion-first reduced reoffending 28% over 24 months, consistent with the national meta-analysis."},
    {"id":"precision-gov-mid-25","level":"mid","profession":"publicservice","title":"Known, estimated, unknown","scenario":"You're giving the duty director a verbal sitrep on a chemical spill at the works yard. In the moment, facts, estimates, and guesses blur together — and a guess repeated upward becomes a fact by the third retelling. You know: contained, no injuries. You estimate: cleanup by midnight. You don't know: the cause.","task":"Say a 3-4 sentence sitrep that explicitly labels what is confirmed, estimated, and unknown.","tips":["Three registers, spoken as three: 'Confirmed... Our estimate... Not yet known...'","Labelled uncertainty is precision; unlabelled confidence is a liability.","Say when the unknowns get answers — that turns gaps into a plan."],"focus":["precision","clarity"],"placeholder":"Confirmed: the spill is contained and there are no injuries. Estimated: cleanup done by midnight. Not yet known: the cause —"}
  ],
  "executive-presence": [
    {"id":"presence-gov-mid-01","level":"mid","profession":"publicservice","title":"Recommend, don't lay out","scenario":"Your options memo on the winter shelter overflow presents three approaches neutrally and closes with 'happy to discuss.' The director wrote back one line: 'Which one?' You know which one — the church partnership — you just didn't want to own it on paper.","task":"Write the memo's new opening: your recommendation, owned, with the strongest reason attached.","tips":["'I recommend' is the phrase — not 'one option might be.'","Attach the single strongest reason; the comparison table backs it up below.","A recommendation the director can reject is more useful than neutrality they must decode."],"focus":["impact","clarity"],"placeholder":"I recommend the church partnership for overflow capacity — it is the only option operational before the first cold snap."},
    {"id":"presence-gov-mid-02","level":"mid","profession":"publicservice","title":"Signpost the briefing","scenario":"You're briefing the director on the encampment file — a tangle of legal, health, and housing threads. Last time you briefed it, the director interrupted twice to ask where you were going. Signposting fixes that: announce the map, then walk it.","task":"Say the opening 2-3 sentences: the headline, then the named parts you'll cover in order.","tips":["'Three things: the court date, the health order, the housing count' — the map costs one sentence.","Once you announce the map, honour it — no detours.","Signposting reads as command of the file, because it is."],"focus":["structure","clarity"],"placeholder":"Bottom line: we are on track for the July court date. Three things you need: the legal position, the health order, and the housing count."},
    {"id":"presence-gov-mid-03","level":"mid","profession":"publicservice","title":"Fact and judgment, kept apart","scenario":"Your assessment of the contractor dispute blends what happened with what you think: 'The contractor is clearly acting in bad faith by missing the deadline.' The missed deadline is fact. Bad faith is your judgment — maybe right, but it must wear its label or it contaminates the facts around it.","task":"Rewrite the assessment in two sentences: the facts, then the judgment clearly flagged as yours.","tips":["Facts first, unadorned: three deadlines missed, no notice given.","Then the flag: 'My read is —' or 'I judge this to be —.'","Readers trust both halves more when they can tell them apart."],"focus":["precision","clarity"],"placeholder":"The contractor has missed three deadlines without notice. My read: this is positioning for a claim, not a capacity problem."},
    {"id":"presence-gov-mid-04","level":"mid","profession":"publicservice","title":"Owning the error, once","scenario":"Your unit sent a public notice with the wrong date and the director found out from a councillor. Your draft response apologizes four times in three paragraphs and never crisply states what happened or what changed. Grovelling reads as panic; ownership reads as command.","task":"Write a 3-sentence account: what happened, what you've done, what prevents a repeat. One apology, placed well.","tips":["State the error in plain declarative: 'We published the wrong date.'","One apology, then the fix — repetition converts accountability into noise.","The prevention step is what the director actually wants to hear."],"focus":["clarity","impact"],"placeholder":"We published the wrong date — my error in the final check. The correction went out within the hour to all channels, and notices now get a second dated sign-off before release."},
    {"id":"presence-gov-mid-05","level":"mid","profession":"publicservice","title":"Cut the apologetic opener","scenario":"Your emails to the director open with 'Sorry to bother you,' 'I know you're busy, but,' or 'Just a quick question if you have a moment.' Each one spends your authority before your content arrives. You're a supervisor raising legitimate business — the apology is a habit, not a courtesy.","task":"Rewrite three apologetic openers as direct first lines that respect both parties' time.","tips":["'Sorry to bother you' becomes the subject of the actual sentence you came to say.","Deference and clarity aren't opposites — a direct question IS the courtesy.","Save 'sorry' for actual errors; spent on openers, it's worthless when you need it."],"focus":["impact","concision"],"placeholder":"Two items need your call today: the posting approval and the ministry visit date."},
    {"id":"presence-gov-mid-06","level":"mid","profession":"publicservice","title":"Calibrated confidence, out loud","scenario":"In the ops meeting you'll report on whether the new intake process is reducing errors. Early data says yes, but it's six weeks in. Your instinct swings between overclaiming ('it's working') and dissolving into hedges ('it's kind of hard to say'). Calibration is the third way.","task":"Say a 2-3 sentence assessment that states your confidence level and what would firm it up.","tips":["'Early signs are good — errors down a third in six weeks' claims exactly what the data supports.","Name when you'll know more: 'a full quarter tells us if it holds.'","Calibration reads as competence; both overclaiming and mush read as their own kind of weak."],"focus":["precision","impact"],"placeholder":"Early signs are good — errors are down a third in six weeks. I'll call it a trend when we have a full quarter."},
    {"id":"presence-gov-mid-07","level":"mid","profession":"publicservice","title":"Speaking first at the table","scenario":"At the monthly inter-agency table, you tend to wait until three others have spoken, then agree with a modification. Your unit carries half the operational load of this partnership, and your late, derivative interventions undersell it. Today's first item is one you know cold: the referral backlog.","task":"Say the 2-3 sentence intervention you'd open with before anyone else frames the issue.","tips":["Speaking first lets you frame; speaking third makes you a footnote to someone else's frame.","Open with your unit's data — it's standing you already own.","Propose the shape of the solution, not just the description of the problem."],"focus":["impact","structure"]},
    {"id":"presence-gov-mid-08","level":"mid","profession":"publicservice","title":"Disagreeing upward, cleanly","scenario":"The director plans to announce the service-counter consolidation next week. You believe the timing is wrong — the online alternative isn't stable yet, and you have the incident tickets to prove it. Saying nothing is safe for you and bad for the operation. Saying it badly is worse.","task":"Write the 3-4 sentence message that states your disagreement, the evidence, and your alternative — respectfully and without hedging it into mush.","tips":["Name the disagreement plainly: 'I recommend we hold the announcement.'","Evidence, not adjectives: 40 unresolved tickets, two outages this month.","Offer the condition that changes your view — it shows this is judgment, not resistance."],"focus":["clarity","impact"],"placeholder":"I recommend we hold the announcement two weeks. The online channel logged two outages and 40 unresolved tickets this month; announcing now routes angry residents to a system that will drop them."},
    {"id":"presence-gov-mid-09","level":"mid","profession":"publicservice","title":"The qualifier purge, spoken","scenario":"A recording of your last briefing is humbling: 'I just think maybe we should probably look at sort of tightening the process a bit.' Nine words of qualifier around five words of content. Your team hears the qualifiers and concludes the direction is optional.","task":"Say the same direction stripped to its content, with at most one qualifier that earns its place.","tips":["'Just,' 'maybe,' 'probably,' 'sort of,' 'a bit' — none of them carries information here.","Keep a qualifier only if it changes what the listener should do.","Directions without qualifiers get followed; padded ones get interpreted."],"focus":["concision","impact"],"placeholder":"We're tightening the intake check: two signatures on every file, starting Monday."},
    {"id":"presence-gov-mid-10","level":"mid","profession":"publicservice","title":"The committee opener","scenario":"You're presenting the program review to the standing committee — your first time in the chair usually filled by your director. Ten minutes, then questions. Your draft opens with thanks, apologies for the length of the report, and a promise to 'try to keep this brief.' None of that is presence.","task":"Write the first three sentences you'd say: the finding, the number, and the map of the ten minutes.","tips":["Skip the throat-clearing; the chair already introduced you.","First sentence carries the review's verdict — committees remember openings.","Then the map: 'Ten minutes: results, gaps, and the three changes we propose.'"],"focus":["structure","impact"],"placeholder":"The program is delivering — retention is up 13 points — but it is outgrowing its funding model. In ten minutes I'll cover results, gaps, and three proposed changes."},
    {"id":"presence-gov-mid-11","level":"mid","profession":"publicservice","title":"Direction that sounds decided","scenario":"Your shift briefings have drifted into suggestion voice: 'It would be good if folks could try to get reports in on time,' 'We should probably keep an eye on the east lot.' The team hears preferences, not direction — and follows accordingly.","task":"Say two of tonight's directions in decided voice: who does what, by when.","tips":["'Reports are due before end of shift — no exceptions tonight' is direction.","Assign by name where it matters; 'folks' diffuses responsibility to nobody.","You can be warm and decided in the same sentence; you can't be mushy and followed."],"focus":["clarity","impact"]},
    {"id":"presence-gov-mid-12","level":"mid","profession":"publicservice","title":"Claiming the win, calibrated","scenario":"Your unit cleared the permit backlog two months early — genuinely your team's redesign, though a system upgrade helped. In your report you're tempted to bury it in passive modesty: 'the backlog was resolved.' The other temptation: a victory lap that annoys peers who know about the upgrade.","task":"Write 2-3 sentences that claim the result accurately — your team's work, the assist acknowledged.","tips":["Name the result and your team's specific move: the triage redesign.","Credit the assist in one clause; honesty about help makes the claim stronger.","'Was resolved' donates your team's win to the passive voice — don't."],"focus":["precision","impact"],"placeholder":"The team cleared the backlog two months early — the triage redesign cut handling time 40%, with an assist from the March system upgrade."},
    {"id":"presence-gov-mid-13","level":"mid","profession":"publicservice","title":"Standing your ground on the data","scenario":"In the budget review, a senior manager waves off your overtime analysis: 'Those numbers don't feel right.' The numbers are right — you pulled them yourself from payroll. Folding here costs the argument; bristling costs the room. The move is calm specificity.","task":"Say a 2-3 sentence response that holds the ground with sources, not volume.","tips":["Restate the number with its source: payroll extract, all twelve months.","Offer verification, not defensiveness: 'happy to walk through the pull.'","Calm plus specific beats loud plus general in every meeting ever held."],"focus":["precision","impact"],"placeholder":"The figures come straight from the payroll extract, all twelve months. I'm confident in them — and glad to walk through the pull line by line."},
    {"id":"presence-gov-mid-14","level":"mid","profession":"publicservice","title":"A position with a tripwire","scenario":"The director asks whether to expand the pilot to the north district now or wait for the full evaluation. You lean expand — the interim results are strong — but real uncertainty remains. Presence under uncertainty is a position plus the specific thing that would change it.","task":"Write a 2-3 sentence recommendation that takes the position and names your reversal condition.","tips":["Take the position: 'Expand now.' The hedge goes in the tripwire, not the verb.","Name the condition that flips you: 'if Q3 completion drops below 70%, pause.'","A position with a tripwire is confidence plus honesty — the executive combination."],"focus":["clarity","impact"],"placeholder":"Expand to the north district now — interim results justify it. One tripwire: if Q3 completion drops below 70%, we pause before adding a third site."},
    {"id":"presence-gov-mid-15","level":"mid","profession":"publicservice","title":"'I' where it counts","scenario":"Your memo recommending the vendor switch says 'it is felt that,' 'the team believes,' and 'it was concluded.' You wrote it, you concluded it, and you'll defend it. Diffusing ownership into the passive and the collective reads as pre-positioned deniability.","task":"Rewrite the three phrases so the recommendation has an owner.","tips":["'It is felt that' has no address; 'I recommend' does.","Use 'we' for the team's work, 'I' for the judgment — precision about ownership is presence.","If you wouldn't sign it as yours, the problem is the recommendation, not the pronoun."],"focus":["clarity","impact"],"placeholder":"The team ran the evaluation; I reviewed the scores and I recommend switching to Vendor B at contract end."},
    {"id":"presence-gov-mid-16","level":"mid","profession":"publicservice","title":"The voicemail without the wobble","scenario":"You're calling the deputy director's office to escalate the facility heating failure before tonight's cold snap. Your rehearsed message keeps ending sentences on a rising, uncertain note: 'so we might need to look at relocating? if that's okay?' The situation needs a supervisor who has decided.","task":"Script the 3-sentence voicemail in decided, falling-cadence sentences.","tips":["Statements end down; requests are still statements: 'I need a callback by 4.'","Say what you've already decided and done — presence is momentum.","'If that's okay' surrenders a decision you were paid to make."],"focus":["clarity","impact"],"placeholder":"It's Morgan at the Elm Street centre. Heating has failed with a cold snap due tonight — I've started relocation planning for 40 residents and I need your callback by 4 to authorize transport."},
    {"id":"presence-gov-mid-17","level":"mid","profession":"publicservice","title":"The verdict sentence","scenario":"Your program evaluation's executive summary opens: 'This review examined multiple dimensions of program performance across several domains.' That's a table of contents wearing a sentence. The review's actual verdict: the program works but is funded to fail — demand doubled, budget flat.","task":"Write the verdict sentence that should open the summary.","tips":["A verdict sentence could be disagreed with — that's how you know it says something.","'Examined multiple dimensions' describes your effort; verdicts describe the world.","Every strong summary can be reduced to one sentence someone might fight."],"focus":["impact","clarity"],"placeholder":"The program works but is funded to fail: demand has doubled while the budget has stayed flat."},
    {"id":"presence-gov-mid-18","level":"mid","profession":"publicservice","title":"Taking the meeting back","scenario":"You're chairing the coordination meeting and two attendees have hijacked item one with a fifteen-minute argument about a parking policy that isn't on the agenda. The rest of the room is checking phones. Taking control without humiliating anyone is a sentence, not a struggle.","task":"Say the 1-2 sentence intervention that returns the meeting to its agenda.","tips":["Name what's happening without blame: 'this one needs its own conversation.'","Park it visibly — offer the follow-up so the interruptors don't lose face.","Then re-anchor: restate the item and the decision it needs."],"focus":["clarity","structure"],"placeholder":"I'm going to park the parking question — it deserves its own meeting and I'll set it up this week. Back to the referral backlog: we need a decision on coverage today."},
    {"id":"presence-gov-mid-19","level":"mid","profession":"publicservice","title":"A date, or a date for a date","scenario":"The director asks when the staffing review lands. It isn't done and several inputs are outside your control. The weak answers: an evasive 'soon' or a fake-confident date you'll miss. The presence answer commits to something you fully control.","task":"Say the 1-2 sentence answer that gives either a real date or a date for a date.","tips":["'I'll have HR's numbers Friday; you'll have the review or a firm date by Monday noon.'","Never trade credibility for a comfortable meeting — a missed date costs more than honesty now.","A date-for-a-date is a commitment, not a dodge, when you keep it."],"focus":["precision","clarity"],"placeholder":"HR's numbers arrive Friday. By Monday noon you'll have either the full review or a firm delivery date — my commitment."},
    {"id":"presence-gov-mid-20","level":"mid","profession":"publicservice","title":"The ministry letter, measured","scenario":"The ministry's compliance office queried your unit's reporting discrepancy in a letter with an edge to it. Your draft reply oscillates between defensive ('at no time did this unit') and obsequious ('we deeply regret any inconvenience'). The register that serves you is neither: factual, unruffled, complete.","task":"Write the reply's opening 2-3 sentences in that measured register.","tips":["State the facts of the discrepancy and its cause without adjectives.","Neither grovel nor bristle — both registers invite escalation.","Close the opening with what was corrected and when; competence is the best tone."],"focus":["audience","precision"],"placeholder":"The discrepancy in the Q2 submission traces to a duplicated extract on our side. It was identified June 3, corrected June 5, and the revised figures are attached."},
    {"id":"presence-gov-mid-21","level":"mid","profession":"publicservice","title":"Finishing the sentence","scenario":"At the inter-agency table, a senior manager from the lead agency talks over you mid-recommendation — the third time this meeting. Your options: subside (your unit's position goes unmade), match volume (you lose the room), or hold the floor with calm economy.","task":"Say the sentence that holds the floor and completes your point.","tips":["'Let me land this point, then I want your take' holds ground and offers respect.","Keep your voice at the same volume — the contrast does the work.","Then deliver the point in one sentence; you've spent the room's attention to get here."],"focus":["impact","concision"]},
    {"id":"presence-gov-mid-22","level":"mid","profession":"publicservice","title":"Inviting the fight, on purpose","scenario":"Your recommendation memo on consolidating the two intake offices is solid but contested — the east office's supervisor will hate it. The weak move is softening the recommendation until it offends no one and says nothing. The presence move: state it plainly and invite the disagreement explicitly.","task":"Write the closing 2 sentences: the restated recommendation and the genuine invitation to challenge it.","tips":["Restate the position at full strength — the invitation is not a retreat.","'The strongest case against is X; if anyone can add to it, I want it before Friday' invites real challenge.","Inviting disagreement from strength is presence; softening to avoid it is camouflage."],"focus":["impact","clarity"],"placeholder":"My recommendation stands: consolidate intake at the west office by Q1. The strongest counter-argument is east-side travel time — if anyone can strengthen that case, I want it before Friday's decision."},
    {"id":"presence-gov-mid-23","level":"mid","profession":"publicservice","title":"Opening the town hall","scenario":"You're opening the public meeting on the supervised-consumption site — a room of 200, some furious. Your director is away; you're the face. The opener must do three things in under a minute: own the room, name the anger honestly, and set the rules of the evening without sounding like a bouncer.","task":"Say the opening 3-4 sentences.","tips":["Acknowledge the heat honestly in the first breath — pretending it's a routine meeting insults the room.","State what tonight will and won't decide; false hope is fuel.","Set the format as a promise, not a rule: 'everyone who lines up speaks.'"],"focus":["audience","impact"]},
    {"id":"presence-gov-mid-24","level":"mid","profession":"publicservice","title":"Correcting the record, without the edge","scenario":"In the directors' meeting, a peer just summarized your unit's position as 'they oppose the merger' — flat wrong; you support it with two conditions. Let it stand and the minutes make it true. Correct it with an edge and you've made an enemy over a paraphrase.","task":"Say the 1-2 sentence correction that fixes the record cleanly.","tips":["Correct the substance, not the person: 'Small correction to be safe —.'","Restate your actual position in one sentence so the minutes catch it.","Speed matters: correct it now, in the room, not by email tomorrow."],"focus":["clarity","precision"],"placeholder":"Small correction for the record: we support the merger — with two conditions, staffing parity and a single intake queue."},
    {"id":"presence-gov-mid-25","level":"mid","profession":"publicservice","title":"The close that assigns the next move","scenario":"Your memos end with 'Let me know your thoughts' and 'Happy to discuss further.' The result: silence, then a follow-up, then a hallway ambush three weeks later. A memo with presence ends by assigning the next move — what you need, from whom, by when.","task":"Rewrite the closing 1-2 sentences of a decision memo with a specific next step and date.","tips":["'Let me know your thoughts' asks for nothing and gets it.","Name the decision, the decider, and the date — then say what happens if you hear nothing.","A default-forward close ('unless I hear otherwise by Friday, I'll proceed') moves stalled files."],"focus":["impact","concision"],"placeholder":"I need your approval on the staffing option by Friday, June 20. Unless I hear otherwise by then, I'll proceed with Option B and post the positions Monday."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-gov-mid-01","level":"mid","profession":"publicservice","title":"The councillor's yes-or-no","scenario":"At committee, a councillor asks you directly: 'Will the warming centres open by November 1 — yes or no?' The honest answer is yes for three of four sites; the fourth depends on a fire inspection. Your instinct is to explain the inspection process first. The room hears that as a dodge.","task":"Say the answer with the direct part first and the one condition second, in 2 sentences.","tips":["Lead with what's true and direct: 'Yes for three of the four.'","The condition is one clause, not a process explanation.","Committees forgive complexity; they punish evasion."],"focus":["clarity","precision"],"placeholder":"Yes for three of the four sites. The fourth — Hillcrest — opens November 1 if it passes fire inspection on October 20, and we have a backup if it doesn't."},
    {"id":"pressure-gov-mid-02","level":"mid","profession":"publicservice","title":"'Will it be ready by winter?'","scenario":"The director asks point-blank whether the shelter expansion will be operational by winter. The truth: the building will be, but staffing won't unless the hiring freeze exemption comes through in the next three weeks. 'Yes' is a lie; 'it's complicated' is a fog. The real answer is a shaped risk.","task":"Say the 2-3 sentence answer: the direct part, the specific risk, and what would resolve it.","tips":["Split the question honestly: building yes, staffing conditional.","Name the single gating item and its date — that's the actionable part.","An answer shaped as a risk gives the director something to fix; mush gives them something to fear."],"focus":["clarity","impact"],"placeholder":"The building, yes. Staffing, only if the freeze exemption lands in three weeks — that is the one thing standing between us and a November open."},
    {"id":"pressure-gov-mid-03","level":"mid","profession":"publicservice","title":"The furious resident at the mic","scenario":"At the community meeting, a resident stands up shaking: 'My mother waited nine hours for your emergency line. Nine hours. What do you people even do?' The room goes quiet. Defending the call system now would be accurate and catastrophic. The question under the question: does anyone care what happened to her?","task":"Say your first 2-3 sentences in response.","tips":["Answer the human question first — acknowledge the nine hours as real and wrong.","No system explanation in the first breath; it reads as the machine defending itself.","Commit to the specific follow-up: her case, your desk, this week — then the systemic answer."],"focus":["audience","impact"]},
    {"id":"pressure-gov-mid-04","level":"mid","profession":"publicservice","title":"'I don't know' with a path","scenario":"Mid-briefing, the director asks how many of the flagged files involve repeat addresses. You don't know — the data exists but you haven't cut it that way. Bluffing a number is career Russian roulette; a bare 'I don't know' hangs in the air. The strong version has three parts.","task":"Say the answer: the honest gap, how you'll close it, and by when.","tips":["Clean admission first — no wince, no filler.","Name the method: 'the case system tracks addresses; it's a one-day pull.'","The deadline converts ignorance into a work plan."],"focus":["clarity","precision"],"placeholder":"I don't know the repeat-address count yet. The case system can cut it that way — I'll have the number to you by tomorrow noon."},
    {"id":"pressure-gov-mid-05","level":"mid","profession":"publicservice","title":"The media question with an hour on the clock","scenario":"Comms forwards a reporter's question due in an hour: 'Is it true the department knew about the bridge deficiency two years before the closure?' The truthful answer is layered: an inspection flagged wear in 2024, rated non-critical under the standard then in force; the critical rating came this spring. One wrong word becomes the headline.","task":"Write the 2-3 sentence response for comms — direct, precise, quotable without distortion.","tips":["Answer the actual question first: what was known, when, at what rating.","Every sentence must survive being quoted alone — test each one.","Precision about the standard is your defence; defensiveness is their headline."],"focus":["precision","audience"],"placeholder":"A 2024 inspection identified wear and rated it non-critical under the applicable standard. The rating changed to critical in this spring's inspection, and the bridge was closed within 48 hours of that finding."},
    {"id":"pressure-gov-mid-06","level":"mid","profession":"publicservice","title":"'What are you hiding?'","scenario":"At the public meeting on the site selection, an attendee demands: 'The scoring matrix was never published. What are you hiding?' The matrix wasn't published because it contains a landowner's commercial information — a boring, legitimate reason that will sound like a cover-up if you deliver it defensively.","task":"Say a 2-3 sentence answer that meets the accusation with openness instead of armor.","tips":["Don't repeat the accusation ('we're not hiding anything') — answer past it with facts.","Give the boring reason plainly and quickly; speed reads as innocence.","Offer the disclosure you CAN make — the redacted matrix, the criteria list — and a date."],"focus":["audience","clarity"],"placeholder":"The matrix includes one landowner's commercial terms, which we can't publish. Everything else can be released — the criteria, weights, and scores go on the website this week with that one column redacted."},
    {"id":"pressure-gov-mid-07","level":"mid","profession":"publicservice","title":"The union rep's pointed question","scenario":"In the joint committee meeting, the union rep asks: 'Three members have left this unit in four months. When does management admit there's a workload problem?' There is a workload problem — you've been escalating it for two quarters. Agreeing carelessly undercuts your director; denying it insults the room's intelligence.","task":"Say a 2-3 sentence answer that is honest about the problem without torching the chain of command.","tips":["Concede the fact pattern — three departures is not in dispute.","Speak to what you own: the escalation you've made and the interim steps you control.","Never promise what isn't yours to give; name where the decision actually sits."],"focus":["audience","precision"],"placeholder":"The workload is real and I've escalated it formally twice this year. What I control today is the rotation and the backfill priority — here's what changes this month."},
    {"id":"pressure-gov-mid-08","level":"mid","profession":"publicservice","title":"'Why should we trust your numbers?'","scenario":"At the budget review, a finance committee member says: 'Last year you projected $80K in overtime and spent $130K. Why should we believe this year's figure?' A general apology answers nothing; the trust question needs a specific cause and a changed method.","task":"Say the 3-sentence answer: the specific cause of last year's miss, what changed in how you project, and the new number's basis.","tips":["Name last year's driver precisely — an unbudgeted 6-week emergency deployment.","The trust answer is the method change, not the apology.","Show the new number's arithmetic in one clause: staffing plan times known rates."],"focus":["precision","impact"],"placeholder":"Last year's miss was the flood deployment — six unbudgeted weeks. This year's projection is built shift-by-shift from the approved staffing plan, and it includes a contingency line for exactly that kind of event."},
    {"id":"pressure-gov-mid-09","level":"mid","profession":"publicservice","title":"The question with a false premise","scenario":"A committee member asks: 'Why did your unit cut the seniors' transit program?' The unit didn't cut it — the program moved to a regional provider with expanded hours. Answer the 'why' and you've confirmed a cut that never happened; the premise has to be corrected first, without lecturing.","task":"Say the 2-sentence answer: premise corrected, real question answered.","tips":["Correct fast and without triumph: 'The program wasn't cut — it moved.'","Then answer the concern underneath: is service better or worse for seniors?","Never build an answer on a premise you know is false; it becomes yours."],"focus":["clarity","precision"],"placeholder":"The program wasn't cut — it transferred to the regional provider in April with longer hours. The real question is whether seniors are better served, and the early numbers say yes: ridership is up 12%."},
    {"id":"pressure-gov-mid-10","level":"mid","profession":"publicservice","title":"The three-part question","scenario":"The deputy fires a compound question: 'Where are we on the backlog, what's it costing us, and why wasn't the June target hit?' Answered as a blur, all three answers weaken each other. Answered as three labelled parts, the same content sounds like command of the file.","task":"Say the answer structured as three explicit parts, one or two sentences each.","tips":["Signpost the split: 'Three answers.' Then number them aloud.","Answer in the asked order unless one is urgent — then say you're reordering and why.","The third answer — the miss — gets the same directness as the first two, not extra padding."],"focus":["structure","clarity"],"placeholder":"Three answers. Backlog: 240 files, down from 390. Cost: about $9K a month in overtime. The June miss: two processors left in May and the backfill took six weeks."},
    {"id":"pressure-gov-mid-11","level":"mid","profession":"publicservice","title":"The loaded question at the hearing","scenario":"At the licensing hearing, an objector asks: 'How many more incidents will it take before your department does its job?' Any direct answer to the question as asked accepts its framing — that the department isn't doing its job. You need to answer the legitimate concern inside the hostile wrapper.","task":"Say a 2-3 sentence response that extracts and answers the real question.","tips":["Name the legitimate core: 'the real question is whether enforcement is working.'","Answer that with the record: inspections done, orders issued, the trend.","Stay off the bait; the room judges your temperature, not your comeback."],"focus":["audience","impact"]},
    {"id":"pressure-gov-mid-12","level":"mid","profession":"publicservice","title":"The bridge that isn't a dodge","scenario":"A reporter at the scrum asks about staff morale after the restructuring — a question you can't fully answer without discussing personnel matters. Pure deflection ('I won't discuss that') sounds guilty. The honest bridge answers what you can, names what you can't, and explains why.","task":"Say the 2-3 sentence response: the answerable part answered, the limit named with its reason.","tips":["Answer the real fraction: turnover figures, the survey you're running.","Name the limit honestly: individual personnel matters stay private, and say why.","A visible reason for the limit is the difference between discretion and stonewalling."],"focus":["audience","precision"],"placeholder":"I can tell you turnover is at 8%, in line with the two years before the restructuring, and we survey staff next month. What I won't discuss is individual personnel matters — those stay private for the staff's sake, not mine."},
    {"id":"pressure-gov-mid-13","level":"mid","profession":"publicservice","title":"'It depends' — made useful","scenario":"The director asks how long the encampment relocation will take. It genuinely depends — on court timing and on how many residents accept housing offers. 'It depends' alone is an answer-shaped hole. Bounded scenarios turn the same uncertainty into something the director can plan around.","task":"Say the answer as two or three bounded scenarios with the variable that selects between them.","tips":["'If the injunction holds, three weeks; if appealed, ten to twelve' — that's 'it depends' with handles.","Name the selector variable so the director can watch it too.","Uncertainty structured is information; uncertainty raw is noise."],"focus":["precision","structure"],"placeholder":"Two scenarios. If the court order stands: three weeks. If it's appealed: ten to twelve. We'll know which by the 15th."},
    {"id":"pressure-gov-mid-14","level":"mid","profession":"publicservice","title":"The curveball, and the pause","scenario":"Deep in your staffing briefing, the director asks something from left field: 'Could we contract this whole function out?' You have views, but blurting the first three that arrive will sound like panic. A deliberate pause plus a structured first response beats speed every time.","task":"Say the response: an honest framing sentence, your initial read, and the offer of a considered answer.","tips":["'Let me give you my first take, then a considered answer Thursday' buys quality without dodging.","Give a real initial read — total silence until Thursday wastes the moment.","Name the two factors the real answer turns on; that's thinking aloud, structured."],"focus":["clarity","structure"],"placeholder":"My first take: parts of it, yes — the seasonal work; the regulated functions, almost certainly not. Let me bring you a considered answer Thursday with the cost comparison."},
    {"id":"pressure-gov-mid-15","level":"mid","profession":"publicservice","title":"The commitment you can't make","scenario":"At the residents' meeting, the room pushes hard: 'Just promise the road reopens before school starts.' You can't — the utility relocation is outside your control. The room wants the promise; giving it buys tonight and bankrupts September. Hold the line without sounding like a bureaucrat hiding behind process.","task":"Say the 2-3 sentence response that declines the promise and gives what you CAN commit to.","tips":["Say plainly why the promise isn't yours to make — one sentence, no jargon.","Commit to what you control: the weekly public update, the escalation you'll make.","People forgive 'I can't promise that'; they never forgive a broken promise."],"focus":["audience","impact"]},
    {"id":"pressure-gov-mid-16","level":"mid","profession":"publicservice","title":"The question about a colleague's unit","scenario":"At committee, a councillor asks why the permits your unit approved sat six weeks in another unit's queue. True — and saying it that way throws a peer under the bus. Deflecting entirely leaves your unit wearing the delay. The answer owns the system, states the facts, and avoids the adjectives.","task":"Say a 2-3 sentence answer that is accurate about where time went without prosecuting your colleague.","tips":["Facts without blame-adjectives: 'our approval took 9 days; the full process averages 7 weeks end to end.'","Speak as the system's representative: what WE are fixing about the handoff.","The room notices who stays classy under a splitting question — that's the win available here."],"focus":["precision","audience"],"placeholder":"Our approval stage averaged 9 days. The end-to-end process ran 7 weeks, and the two units are now moving to a shared queue so the handoff stops costing residents time."},
    {"id":"pressure-gov-mid-17","level":"mid","profession":"publicservice","title":"'Why wasn't this prevented?'","scenario":"After the depot fire, the director asks the question every incident produces: 'Why wasn't this prevented?' The honest answer is uncomfortable but not damning: the inspection cycle was followed, and the cycle itself was too long for equipment of that age. Defensive answers bury exactly the insight that prevents the next one.","task":"Say the 3-sentence answer: what the record shows, the honest gap, and the fix already moving.","tips":["Establish the followed process first — it's true and it frames the gap correctly.","Name the gap as a system property, not a person's failure.","The credibility of the fix depends on the honesty of the gap."],"focus":["clarity","impact"],"placeholder":"Every scheduled inspection was done on time — the record is clean. The gap is the schedule itself: a 24-month cycle is too long for compressors that age, and I've already moved that class to a 12-month cycle."},
    {"id":"pressure-gov-mid-18","level":"mid","profession":"publicservice","title":"Asked, answered, asked again","scenario":"You've answered the committee member's question about the consultant contract — directly, with the figure. Two minutes later they ask it again, reworded, hunting for a different answer. The trap is elaborating: each new version of your answer creates daylight between versions. The move is the same answer, calmly, shorter.","task":"Say the second response: same substance, fewer words, zero irritation.","tips":["Consistency is the message; variation is the story they're fishing for.","'As I said' scores a point and costs the room — just answer again.","Shorter the second time signals confidence, not evasion."],"focus":["concision","impact"],"placeholder":"The contract was $68,000, competitively awarded, and the deliverables are all on file. That's the complete picture."},
    {"id":"pressure-gov-mid-19","level":"mid","profession":"publicservice","title":"The question you legally can't answer","scenario":"At the community meeting about the closed facility, someone asks whether a named employee was fired over the incident. Privacy law flatly bars you from answering — but 'I can't comment' lands as confirmation to half the room. You need the limit stated so it protects everyone, including the asker's neighbour.","task":"Say the 2-sentence response that holds the legal line without feeding the rumor.","tips":["State the rule as universal, not case-specific: 'employment outcomes are private for every employee, in every case.'","Then redirect to what IS public: the incident findings and the facility changes.","The universal framing is what stops 'no comment' from becoming 'yes.'"],"focus":["audience","precision"],"placeholder":"Employment matters are private for every employee, in every case — so I won't discuss any individual, and you'd want the same if it were you. What I can share fully is what the review found and what changed at the facility."},
    {"id":"pressure-gov-mid-20","level":"mid","profession":"publicservice","title":"Their number versus yours","scenario":"At the hearing, an objector cites 'forty violations at this site' — from a database that counts every complaint as a violation. Your records: 40 complaints, 6 substantiated violations, 4 corrected. Dismissing their number insults them; accepting it concedes a false record. Reconcile the numbers out loud.","task":"Say a 2-3 sentence response that explains both numbers and lands the accurate one.","tips":["Honour their number's source before correcting its meaning — they didn't invent it.","Walk the funnel: 40 complaints, 6 substantiated, 4 corrected, 2 in progress.","The reconciliation is more convincing than either number alone."],"focus":["precision","clarity"],"placeholder":"Both numbers are real — they're counting different things. Forty complaints were filed; six were substantiated as violations, four are corrected, and two are on compliance deadlines this month."},
    {"id":"pressure-gov-mid-21","level":"mid","profession":"publicservice","title":"The personal attack at the mic","scenario":"During the Q&A on the shelter siting, a speaker turns personal: 'You don't live here. You get paid either way. Why would anyone trust a word you say?' Nothing about the project — all about you. Answering the attack keeps the meeting on you; the skill is one honest beat, then back to substance.","task":"Say the response: one sentence that meets the attack as a person, then the pivot to the decision at hand.","tips":["One human beat — 'fair to ask who I am in this' — no résumé recital.","Don't defend your salary or your postal code; the room isn't voting on those.","The pivot names what the decision actually turns on, and invites them into it."],"focus":["audience","impact"]},
    {"id":"pressure-gov-mid-22","level":"mid","profession":"publicservice","title":"The deadline demand, mid-crisis","scenario":"Four hours into the water-main failure, the mayor's office calls: 'When is it fixed? We're telling media in ten minutes.' The crew's honest estimate is 'tonight, probably' — the contractor hasn't confirmed the part. What you say next gets broadcast. Overpromise and tonight's miss is tomorrow's story.","task":"Say the 2-sentence answer that gives them something broadcastable without betting on the unconfirmed part.","tips":["Give the bounded version: 'service back overnight, confirmed timeline by 6 p.m.'","Name the next update time — media can work with a rhythm, not a shrug.","The quote you'd want read back tomorrow is the one to say now."],"focus":["precision","audience"],"placeholder":"Crews expect service restored overnight, and we'll confirm a firm time by 6 p.m. Next update at 6 — that's the line I'd give media."},
    {"id":"pressure-gov-mid-23","level":"mid","profession":"publicservice","title":"The overtime grilling","scenario":"The finance committee has your overtime numbers on the screen and a member is walking through them line by line: 'March, $14K. April, $19K. Explain each one.' You know the drivers cold — vacancies, one deployment, minimum staffing. The pressure move they want is flustered detail; the answer is the pattern.","task":"Say a 3-sentence answer that gives the pattern behind the line items before returning to any single month.","tips":["Zoom out first: one cause explains 80% of the lines — say so.","Offer the line-by-line in writing; committees rarely actually want it live.","Knowing the pattern IS the command of detail they're testing for."],"focus":["structure","precision"],"placeholder":"Every month on that screen has the same driver: three vacancies against a minimum-staffing floor. The two spikes — April and June — add one flood deployment each. I'll table the line-by-line, but that's the whole pattern."},
    {"id":"pressure-gov-mid-24","level":"mid","profession":"publicservice","title":"Honest without ambushing your director","scenario":"At the public accounts session, you're asked whether your unit requested more funding before the service failure. You did — twice, in writing — and the director's office declined it. The truth serves the record; delivered rawly, it detonates under your director on live stream. There is a version that is both honest and fair.","task":"Say the 2-sentence answer that states the fact without editorializing the decision.","tips":["The fact, in neutral voice: requests were made; the envelope couldn't accommodate them that year.","Skip the adjectives — 'repeatedly denied' testifies against; 'made and not funded' testifies.","Fairness to the decision-maker's context is honesty too: every request competes with others."],"focus":["precision","audience"],"placeholder":"Yes — the unit submitted funding requests in both budget cycles. They weren't funded within that year's envelope, which had to cover competing pressures across the division."},
    {"id":"pressure-gov-mid-25","level":"mid","profession":"publicservice","title":"Thirty seconds, three questions","scenario":"You step out of the incident command post and a reporter catches you: 'What happened, is anyone hurt, and when will residents get answers?' Live camera, thirty seconds, no comms officer in sight. Three questions, three short answers, no speculation — then stop talking.","task":"Say the three answers in under thirty seconds of speech.","tips":["Answer in their order: what, injuries, next information point.","Only confirmed facts — the camera never forgets a guess.","End with the update commitment and stop; trailing off invites the fourth question."],"focus":["concision","clarity"],"placeholder":"A transformer failure cut power to about 600 homes. No injuries reported. Residents get a full update at 7 p.m. at the community centre and on the city channels."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-gov-mid-01","level":"mid","profession":"publicservice","title":"The before/after for the funding ask","scenario":"Your request for two intake case workers is drafted as a list of workload statistics. True, and inert. The persuasive frame is the contrast: today a family in crisis waits 11 days for a first appointment; funded, they wait 3. The director should see both worlds and the bridge between them.","task":"Write the 3-sentence before/after framing for the request.","tips":["Paint 'today' in one concrete sentence — the 11-day wait, what happens during it.","Paint 'funded' in one sentence — the 3-day wait and what it prevents.","The ask is the bridge: two positions, $148K, live by January."],"focus":["impact","structure"],"placeholder":"Today, a family in crisis waits 11 days for a first appointment — long enough for an eviction to finish. With two more case workers, that wait is 3 days."},
    {"id":"narrative-gov-mid-02","level":"mid","profession":"publicservice","title":"The stakes, made human","scenario":"Your briefing note argues for extending the cooling-centre hours and cites 'elevated heat-related morbidity among vulnerable populations.' Nobody has ever funded a morbidity abstraction. Last July, paramedics carried a 78-year-old out of a top-floor walk-up two blocks from a centre that had closed at 5 p.m. That is the stake.","task":"Rewrite the stakes passage in 2-3 sentences pairing the human case with the scale number.","tips":["One person, specifically drawn, stands in for the statistic — then give the statistic its turn.","'Two blocks from a closed centre' is the argument; let the detail do it.","Human stakes without the scale number reads as anecdote; pair them."],"focus":["impact","audience"],"placeholder":"Last July, paramedics carried a 78-year-old out of a top-floor walk-up two blocks from a cooling centre that had closed at 5 p.m. Heat calls after 5 p.m. numbered 340 last summer."},
    {"id":"narrative-gov-mid-03","level":"mid","profession":"publicservice","title":"Disarming the objection you know is coming","scenario":"Your proposal to consolidate the two counters will draw one objection before any other: east-side residents lose their nearby office. It's the first thing the director will think and the first thing council will ask. A proposal that doesn't raise and answer it first looks like it hasn't noticed.","task":"Write the 2-3 sentence passage that names the strongest objection and answers it head-on.","tips":["Raise it yourself, at full strength — a strawman version fools nobody.","Answer with the mitigation: the mobile service day, the transit reality, the usage data.","Owning the objection converts your biggest critic's point into your credibility."],"focus":["impact","structure"],"placeholder":"The strongest objection is real: east-side residents lose their walk-in counter. Two things answer it — 71% of east-side visits are for services now available online or by phone, and a weekly mobile counter will serve the rest at the library."},
    {"id":"narrative-gov-mid-04","level":"mid","profession":"publicservice","title":"The change story for a tired team","scenario":"You're rolling out the third process change this year, and the team's faces already say 'here we go again.' A feature list will bounce off. What lands is the from/to story told in their day: from re-keying every file twice and eating the blame for mismatches, to entering once and owning a number that's actually theirs.","task":"Say the 3-4 sentence version of the change story you'd open the team meeting with.","tips":["Start in their current pain, named specifically enough that they nod.","The 'to' state is their day improved, not the system's architecture.","Be honest about the transition cost — a bumpy fortnight — or lose them at the first bump."],"focus":["audience","impact"]},
    {"id":"narrative-gov-mid-05","level":"mid","profession":"publicservice","title":"The three-minute deputation","scenario":"You have three minutes before council to make the case for the derelict-property enforcement program before the vote. Three minutes is a story, not a report: the block that turned around, the number that proves it wasn't luck, the ask that keeps it going.","task":"Write the deputation's opening and closing sentences — the hook and the ask.","tips":["Open inside the story: 'Two years ago, Fairview Avenue had six boarded houses.'","Close on the ask with the vote named: 'renew the program at $200K — item 7 tonight.'","Everything between hook and ask serves one arc; cut what doesn't."],"focus":["impact","structure"],"placeholder":"Two years ago, Fairview Avenue had six boarded-up houses and the highest call volume in the ward. Tonight it has none — and item 7 decides whether that program continues."},
    {"id":"narrative-gov-mid-06","level":"mid","profession":"publicservice","title":"The cost of doing nothing","scenario":"Your culvert-replacement proposal keeps losing to flashier capital projects because its benefit is an absence — the flood that doesn't happen. The persuasive move is pricing the status quo: doing nothing isn't free, it's a 1-in-5 annual chance of a washout that costs $2M and closes the only road to 400 homes.","task":"Write the 2-3 sentence passage that makes 'do nothing' a priced option instead of a default.","tips":["Give inaction a price tag and a probability — it becomes a choice someone must own.","Compare like with like: $180K now versus expected $400K a year in risk.","Name who is stranded when it fails; abstract infrastructure has no constituency, roads to homes do."],"focus":["impact","precision"],"placeholder":"Doing nothing has a price: a 1-in-5 annual chance of a washout that costs $2M to repair and cuts the only road to 400 homes. The replacement costs $180K."},
    {"id":"narrative-gov-mid-07","level":"mid","profession":"publicservice","title":"Pilot results into a story arc","scenario":"The community paramedic pilot worked: 30% fewer repeat 911 calls among enrolled seniors, ER visits down, and one paramedic who now knows forty clients by name. Your results deck is a wall of charts. For the decision meeting, the charts need a spine: what we tried, what happened, what it means, what's next.","task":"Write the four-sentence spine that the charts will hang from.","tips":["One sentence per beat: tried, happened, means, next.","Put the strongest number in beat two and the human detail in beat three.","'What it means' is the sentence decks always skip — the interpretation IS the persuasion."],"focus":["structure","impact"],"placeholder":"We asked whether weekly paramedic visits could keep frequent 911 callers stable at home. Among 60 enrolled seniors, repeat calls fell 30% and ER visits fell by a quarter."},
    {"id":"narrative-gov-mid-08","level":"mid","profession":"publicservice","title":"Recruiting the reluctant partner agency","scenario":"You need the housing authority to co-staff the new navigation desk. They've heard pitches before and their default is polite deferral — every partnership costs them staff time they don't have. The persuasion isn't your program's virtue; it's their problem your desk solves: the 200 misdirected applications a year that land on their intake team.","task":"Write the 3-sentence pitch framed entirely around their operational pain.","tips":["Open with THEIR number: 200 misdirected applications their staff currently untangle.","Your desk is the mechanism, not the hero, of the story.","Make the ask small and reversible: one staffer, two afternoons, 90-day review."],"focus":["audience","impact"],"placeholder":"Your intake team untangles about 200 misdirected housing applications a year — ours sends them. A shared navigation desk catches those at the front door instead."},
    {"id":"narrative-gov-mid-09","level":"mid","profession":"publicservice","title":"Persuading the skeptical director","scenario":"Your director thinks the outreach van is 'feel-good spending' and wants the money moved to enforcement. You have the data — van contacts precede 60% of voluntary shelter entries — but data alone hasn't moved them in two meetings. The frame that fits this director: the van as the cheapest stage of the enforcement pipeline they already believe in.","task":"Write the 2-3 sentence reframe that positions the van inside the director's own priorities.","tips":["Persuasion meets people where they stand; find the value THEY hold that your case serves.","'Every voluntary entry the van produces is an encampment removal we don't pay for' — their currency.","This isn't spin if it's true; it's translation."],"focus":["audience","impact"],"placeholder":"The van is the cheapest stage of the enforcement pipeline: 60% of voluntary shelter entries start with a van contact, and every voluntary entry is a removal we never have to staff, document, or defend."},
    {"id":"narrative-gov-mid-10","level":"mid","profession":"publicservice","title":"'Why now' without alarm","scenario":"The records-storage migration has been deferrable for three years, which is exactly why it keeps being deferred. This year it stops being deferrable: the vendor ends support in 14 months and a migration takes 12. Your memo needs urgency that reads as arithmetic, not arm-waving.","task":"Write the 2-sentence 'why now' passage built on the timeline collision.","tips":["Urgency from subtraction: 14 months of support minus 12 months of migration equals now.","No adjectives — 'critical' and 'urgent' are what people write when they can't do the math.","Name the cost of missing the window: an unsupported system holding statutory records."],"focus":["impact","precision"],"placeholder":"Vendor support ends in 14 months and the migration takes 12. The window to start is this quarter — after that, statutory records sit on an unsupported system."},
    {"id":"narrative-gov-mid-11","level":"mid","profession":"publicservice","title":"The audit finding as a mandate","scenario":"The internal audit dinged your unit on contractor oversight — uncomfortable, and also the best leverage you'll ever have for the monitoring position you've requested twice. The story writes itself if you let it: the auditors have independently priced the gap you've been flagging.","task":"Write the 2-3 sentence memo passage that converts the finding into the case for the position.","tips":["Let the auditors be the witness: their words, quoted, carry what yours couldn't.","Connect finding to fix in one clean line: this position is the management response.","Timing is the persuasion — audit responses get funded; wish lists wait."],"focus":["impact","structure"],"placeholder":"The audit's central finding — contractor oversight relies on a single supervisor's spare hours — is the gap this unit flagged in the last two budget cycles. The monitoring position is the management response that closes it."},
    {"id":"narrative-gov-mid-12","level":"mid","profession":"publicservice","title":"The grant narrative's opening scene","scenario":"Your renewal application for the youth program opens with your organizational history — founding date, mandate, governance. Funders read fifty of these. The one they remember opens in the program's world: a Tuesday night at the drop-in, what almost happened, what happened instead.","task":"Write the application's opening 2-3 sentences as a scene that carries the program's logic.","tips":["Open in the concrete: a night, a kid, a fork in the road the program is built around.","The scene must argue, not just decorate — its details should embody the model.","Then pivot to scale in one sentence: this happens 130 times a year."],"focus":["impact","audience"],"placeholder":"On a Tuesday night in February, a 15-year-old stood outside the drop-in deciding between coming in and the group waiting at the plaza. The program exists for that ten seconds — and it wins them about 130 times a year."},
    {"id":"narrative-gov-mid-13","level":"mid","profession":"publicservice","title":"Persuading the union, honestly","scenario":"You want the union's support for the new fatigue-management schedule. The efficiency framing that sold your director will die in this room. The honest member-side case exists: the current schedule's split shifts are why members burn out and grievances cluster in months 3 and 4 of the rotation. Lead there — because it's true.","task":"Write the 3-sentence opening of the pitch to the union executive.","tips":["Frame in member outcomes: fatigue, grievance clusters, the shifts nobody trades for.","Bring THEIR data — grievance timing — not just management's metrics.","Honest framing survives the members' meeting you won't be in; spin doesn't."],"focus":["audience","impact"]},
    {"id":"narrative-gov-mid-14","level":"mid","profession":"publicservice","title":"From complaint to shared goal","scenario":"The community meeting about the park has become a list of grievances: needles, noise, the broken gate, the lights. You're up next. The persuasive move isn't answering each complaint — it's gathering them into the one story everyone in the room already agrees with: this park used to be theirs, and the plan is to make it theirs again.","task":"Say the 2-3 sentence reframe that turns the grievance list into a shared project.","tips":["Name what the complaints have in common — that's the reframe's raw material.","'Everything said tonight is a version of the same sentence' — then say the sentence.","End by attaching the plan's first visible step to their list; borrowed specifics build trust."],"focus":["audience","impact"]},
    {"id":"narrative-gov-mid-15","level":"mid","profession":"publicservice","title":"The analogy that carries the budget line","scenario":"Council keeps cutting the facilities preventive-maintenance line because its benefit is invisible. Your engineer's explanation — deferred maintenance compounds at 7% — is true and unheard. The analogy that lands: skipping oil changes to save money until the engine seizes. Choose and deploy it without condescending.","task":"Write the 2-sentence passage using one concrete analogy plus the real number.","tips":["One analogy, drawn from a world your audience runs — households, cars, roofs.","Pair it immediately with the actual figure so it informs rather than decorates.","Test the analogy for failure modes; a bad one becomes the counter-argument."],"focus":["audience","impact"],"placeholder":"Cutting preventive maintenance is skipping oil changes: the budget looks better every month until the engine seizes. Our version of the seized engine is the Fairview boiler — $9K of skipped servicing, $210K of emergency replacement."},
    {"id":"narrative-gov-mid-16","level":"mid","profession":"publicservice","title":"One slide, one arc","scenario":"You get one slide in the executive committee's quarterly review to make the case for the intake redesign. The draft slide has four charts and no argument. One slide is a story told in a headline and three beats: the gap, the fix, the payoff — with the ask in the corner where decisions live.","task":"Write the slide: headline, three beats as bullet lines, and the ask line.","tips":["The headline is the argument: 'Intake loses 30% of applicants before first contact.'","Each beat is one line; charts move to the appendix and get pointed at.","The ask carries a number and a date or it's a hope, not an ask."],"focus":["structure","impact"],"placeholder":"Headline: Intake loses 30% of applicants before first contact. Beat 1: The gap —"},
    {"id":"narrative-gov-mid-17","level":"mid","profession":"publicservice","title":"'We tried that in 2019'","scenario":"Your co-response pilot proposal will meet the room's most reliable objection: 'we tried that in 2019 and it flopped.' It did — under different conditions you can name: no dedicated staff, no data-sharing agreement, a six-week timeline. Meet the history head-on or it quietly vetoes you.","task":"Write the 2-3 sentence passage that honors the 2019 attempt and distinguishes this one.","tips":["Concede the failure plainly; revisionism about 2019 costs you the room's historians.","Name the two or three conditions that differ — specifically, checkably.","'Same idea, different machine' is the shape of the argument."],"focus":["structure","impact"],"placeholder":"The 2019 pilot failed, and the review said why: no dedicated staff and no data-sharing agreement. This proposal starts with both — two seconded positions and the MOU signed in March."},
    {"id":"narrative-gov-mid-18","level":"mid","profession":"publicservice","title":"The stakes ladder","scenario":"Your memo on the crumbling retaining wall states the engineering facts and stops. Decision-makers fund consequences, not conditions. The ladder: this year, cracking and monitoring costs; next year, lane closure and liability exposure; the year after, failure risk onto a school route. Each rung has a date and a price.","task":"Write the 3-sentence stakes ladder for the memo.","tips":["One rung per sentence, each with its timeframe and its cost.","Escalate concretely — 'school route' is a rung, 'public safety' is a fog.","The ladder makes early money obviously cheaper; that comparison is the memo's job."],"focus":["structure","precision"],"placeholder":"This year: monitoring and patching, $30K. Within two years: a lane closure on Hill Street and the liability that comes with a known defect. Beyond that: engineered failure risk beside a school route."},
    {"id":"narrative-gov-mid-19","level":"mid","profession":"publicservice","title":"The peer-unit pitch","scenario":"You want the parks unit to co-run the summer youth employment crew — their sites, your recruits. You have no authority over them, only persuasion. Their supervisor's chronic pain: seasonal work orders they can't staff. Your pitch has to arrive as capacity, not as a project they're being volunteered for.","task":"Write the 3-sentence pitch to the peer supervisor.","tips":["Lead with their backlog, in their numbers if you know them.","Make the offer concrete: eight crew members, ten weeks, your supervision included.","Name the escape hatch — a two-week trial — so yes costs them almost nothing."],"focus":["audience","impact"],"placeholder":"You've got a summer work-order backlog; I've got eight funded youth placements and a supervisor for them. Give us your ten most stubborn site jobs for two weeks and see what comes back."},
    {"id":"narrative-gov-mid-20","level":"mid","profession":"publicservice","title":"The renewal story with a face","scenario":"The employment program's renewal deck leads with completion percentages. The story that wins renewals has an arc: where a participant started, what the program did, where they are now — chosen honestly, typical rather than exceptional, and consented. Percentages confirm the story; they can't replace it.","task":"Write the 3-4 sentence participant arc for the renewal presentation.","tips":["Pick the typical case, not the miracle — funders discount miracles.","The middle beat is the program's specific move, not vague 'support.'","Land on the participant's present tense, then hand off to the completion number."],"focus":["impact","audience"]},
    {"id":"narrative-gov-mid-21","level":"mid","profession":"publicservice","title":"'It costs too much' — the cost-shift answer","scenario":"The objection to the supportive-housing contribution is always the same number: $18K per unit per year. The answer is the number nobody says aloud: the same individuals unhoused cost the system $55K a year in emergency services, shelter beds, and enforcement — it's not new money, it's the same money spent worse.","task":"Write the 2-3 sentence response to the cost objection using the cost-shift frame.","tips":["Meet the number with a number; never answer arithmetic with values language.","Name where the $55K currently hides: ER visits, shelter nights, police calls.","'We are already paying — for the worse outcome' is the sentence that turns heads."],"focus":["impact","precision"],"placeholder":"The $18K is real — and the same person unhoused costs this system about $55K a year in ER visits, shelter nights, and enforcement calls. We're already paying; we're just buying the worse outcome."},
    {"id":"narrative-gov-mid-22","level":"mid","profession":"publicservice","title":"Five stories, pick one","scenario":"Your presentation on the navigation program has five client stories, because all five feel unfair to cut. Five stories average each other out; the audience remembers none. Narrative discipline means one story carrying the argument, told properly, with the other four reduced to a single line of scale.","task":"Choose the selection rule, then write the one-line scale sentence that honors the cut stories.","tips":["Select the story whose details embody the program's mechanism, not the most emotional one.","'And versions of this happened 214 times last year' gives the cut stories their line.","The discipline to cut four good stories is what makes the fifth land."],"focus":["concision","impact"],"placeholder":"One story, told fully — then: versions of this happened 214 times last year."},
    {"id":"narrative-gov-mid-23","level":"mid","profession":"publicservice","title":"Moving residents to the new channel","scenario":"The phone-heavy booking system is being replaced with online self-serve, and the notice you inherited reads like a punishment: 'phone bookings will be discontinued.' Persuasion for the public works the same as anywhere: their before, their after, and honest help across the gap for the people the change genuinely costs.","task":"Write the 3-sentence public message: the benefit in their terms, the date, and the bridge for those who can't switch.","tips":["Lead with what residents gain — booking at 9 p.m. in pyjamas, no hold music.","The date is plain; the discontinued part is one clause, not the headline.","The bridge — assisted booking at the library, the seniors' phone line — is what makes the message fair and the change survivable."],"focus":["audience","impact"],"placeholder":"Starting September 2, you can book facility times online anytime — no hold queue, instant confirmation. Phone bookings end October 1, and staffed help stays available at every branch library for anyone who prefers a person."},
    {"id":"narrative-gov-mid-24","level":"mid","profession":"publicservice","title":"Forty-five seconds with the deputy","scenario":"The deputy director is walking to the elevator and you have the walk to make the case for keeping the youth outreach position that's slated for cuts. Forty-five seconds: the stake, the proof, the ask. You will not get a second walk.","task":"Say the 45-second case in 3-4 sentences.","tips":["Open with the stake in one sentence — what disappears with the position.","One number and one instant story; a walk can't hold more.","End with an ask the deputy can grant while the elevator arrives: hold the cut until you've seen the file."],"focus":["concision","impact"]},
    {"id":"narrative-gov-mid-25","level":"mid","profession":"publicservice","title":"From data dump to decision story","scenario":"Your program evaluation deck has 22 slides of findings and a final slide labeled 'Discussion.' The steering committee doesn't need a tour of your data; they need a decision story: here's what we learned, here's what it means, here's the choice, here's our recommendation. The same content, re-plotted.","task":"Write the four section headlines that re-plot the deck as a decision story.","tips":["Each headline is a claim that could be disputed, not a topic label.","The 22 slides redistribute as evidence under the four claims; orphans get cut.","'Discussion' as a finale abdicates — the last headline is your recommendation."],"focus":["structure","impact"],"placeholder":"1. The program reaches the right people. 2. It works — where it's staffed to work. 3. The choice: fund the gap or shrink the mandate. 4."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-gov-mid-01","level":"mid","profession":"publicservice","title":"The peak-season leave denial","scenario":"A reliable staff member requested two weeks off in August — the month your service runs at minimum staffing by policy. You have to say no. Your draft opens with three sentences about how much you value them, and the no arrives so padded it reads like a maybe worth appealing.","task":"Write the 3-sentence decline: the no, the reason, and what you can offer instead.","tips":["The no goes in sentence one — clear enough that no re-ask follows.","One reason, the real one: August minimum staffing, no coverage available.","The alternative must be real: the same weeks in September, first pick for next summer."],"focus":["clarity","audience"],"placeholder":"I can't approve August 4-15 — we're at minimum staffing all month and there's no coverage. I can hold the same two weeks in September for you, and you get first pick of next summer's calendar."},
    {"id":"hard-gov-mid-02","level":"mid","profession":"publicservice","title":"Telling the director the date is gone","scenario":"The records migration will miss its committee-reported deadline by six weeks — a vendor failure, but on your project. The instinct is to soften: 'we may experience some schedule pressure.' The director will stand at a podium with whatever you write; vague costs them more than bad.","task":"Write the 3-sentence message: the miss, the cause, and the recovery date you'd defend.","tips":["'We will miss the September date' — the verb is 'will,' not 'may.'","Cause in one sentence, no adjectives, no lament.","Give the new date you'd stake your name on, plus what makes it solid."],"focus":["clarity","impact"],"placeholder":"We will miss the September migration date by six weeks — the vendor failed its data-validation milestone twice. The defensible new date is November 14, and I've tied their payment schedule to it."},
    {"id":"hard-gov-mid-03","level":"mid","profession":"publicservice","title":"Feedback with a spine","scenario":"A team member's briefing notes keep arriving late and error-ridden — third month running, previously mentioned in passing. Your drafted feedback says they should 'work on attention to detail and time management,' which names no behavior, no impact, and no bar. Vague feedback is a kindness that keeps nobody employed.","task":"Write the 3-sentence feedback: the specific pattern, its concrete impact, and the explicit expectation with a checkpoint.","tips":["Name the pattern with numbers: four of the last six notes late, two with wrong figures.","Impact lands when it's specific: the director quoted a wrong number at committee.","The expectation is a bar plus a date — 'accurate and on time for the next four weeks, review on the 30th.'"],"focus":["precision","clarity"],"placeholder":"Four of your last six briefing notes were late and two had figure errors — one of which the director quoted at committee. Starting now, notes are due complete and checked by the Wednesday deadline. We'll review how it's going on the 30th."},
    {"id":"hard-gov-mid-04","level":"mid","profession":"publicservice","title":"Announcing the program cut to its team","scenario":"Budget direction came down: the family reunification pilot ends in March and its three staff redeploy. You fought it and lost. Now you face the team that built it. They'll remember two things forever: whether you told them straight, and whether you honored the work while doing it.","task":"Say the first 3-4 sentences of the team meeting.","tips":["The decision in sentence one — every minute of preamble is a minute of dread.","Own the message even though you opposed it; 'they decided' invites a fight you can't win for them.","Honor the work specifically, then get concrete fast: what happens to each role, when, and what you'll fight for in redeployment."],"focus":["clarity","audience"]},
    {"id":"hard-gov-mid-05","level":"mid","profession":"publicservice","title":"The non-renewal letter to a grantee","scenario":"A community organization you've funded for six years didn't score high enough in this cycle — the field got stronger, and their outcomes reporting stayed thin. The letter has to survive being read aloud at their board meeting and possibly forwarded to a councillor. Kind, clear, and final, in that order of difficulty.","task":"Write the letter's opening 2-3 sentences.","tips":["The decision arrives in sentence one, unmistakably — hope buried in a maybe is cruelty on layaway.","One true reason at the level they can use: this cycle scored outcomes reporting heavily.","Name what's genuinely available: feedback session, next cycle's dates, transition support."],"focus":["clarity","audience"],"placeholder":"The committee has not renewed your funding for the coming cycle. The scoring weighted measured outcomes heavily this year, and this is where the application fell short of a stronger field. We'd like to offer a feedback session before the fall intake —"},
    {"id":"hard-gov-mid-06","level":"mid","profession":"publicservice","title":"Telling your officer the complaint stands","scenario":"The investigation into a conduct complaint against one of your officers is done: substantiated, with a written reprimand. They're convinced they did nothing wrong, and they'll hear the outcome from you before the letter arrives. The meeting needs the finding delivered clean — not relitigated, not apologized for.","task":"Say the 3-sentence delivery of the finding.","tips":["Finding first, in the investigation's words, not your paraphrase.","Don't reargue the case in the meeting — the finding is made; your job is its clear delivery.","Separate the finding from their future plainly: what the reprimand means and doesn't mean, and their appeal rights."],"focus":["clarity","precision"],"placeholder":"The investigation is complete and the complaint is substantiated — the finding is a written reprimand. I'm not here to reargue it; I'm here to make sure you understand exactly what it says, what it means for you, and your appeal window."},
    {"id":"hard-gov-mid-07","level":"mid","profession":"publicservice","title":"'The bylaw will not change'","scenario":"A resident has written four times about the overnight parking bylaw, each reply from your office more equivocal than the last, each equivocation breeding another letter. The truthful answer is no: council reviewed it last year, it stands, and no further review is scheduled. The kindest reply is the one that ends the correspondence honestly.","task":"Write the 2-3 sentence reply that closes the question with respect and finality.","tips":["A final no, delivered clearly, respects their time more than a fifth maybe.","Give the decision's provenance — council, last year's review — so the no has an address.","Name the one legitimate avenue that remains (a deputation to council), then close."],"focus":["clarity","concision"],"placeholder":"The overnight parking bylaw stands: council reviewed it in 2025 and no further review is scheduled, so I won't hold out the prospect of a change. The avenue that remains open is a deputation to council directly —"},
    {"id":"hard-gov-mid-08","level":"mid","profession":"publicservice","title":"Ending the volunteer's role","scenario":"A long-serving volunteer at the community centre has become a problem: two boundary complaints from staff and a safety-protocol breach with the kids' program. Volunteers can't be fired, exactly — but this one can't stay. Twenty years of service and a hard conversation nobody else will have.","task":"Say the 3-sentence core of the conversation: the decision, the reason, and the acknowledgment.","tips":["The decision is made — say it as made, not as a topic for negotiation.","Reasons at the level of the breaches, without prosecuting each incident in the room.","Honor the twenty years in one true sentence; gratitude and the decision can coexist without weakening each other."],"focus":["clarity","audience"]},
    {"id":"hard-gov-mid-09","level":"mid","profession":"publicservice","title":"The termination notice to the contractor","scenario":"After three cure notices, the cleaning contractor's performance hasn't moved, and you're exercising the termination clause. The letter will be exhibit A if they dispute it. It needs the decision, the contractual basis, the effective date, and the transition requirements — no heat, no hedging, nothing extra.","task":"Write the letter's first two sentences.","tips":["Sentence one: termination, the clause invoked, the effective date.","The record does the arguing: three cure notices, dates cited, deficiencies unremedied.","Anger in a termination letter reads as weakness in a hearing room — keep it at zero degrees."],"focus":["precision","clarity"],"placeholder":"This letter provides notice of termination of Contract 2024-311 under section 14.2, effective August 31. Cure notices issued March 4, April 22, and June 10 identified deficiencies that remain unremedied as of the July inspection."},
    {"id":"hard-gov-mid-10","level":"mid","profession":"publicservice","title":"Withdrawing from the joint pilot","scenario":"Your unit is pulling out of the three-agency data pilot — your legal team killed the sharing agreement. The other two agencies have staff assigned and momentum built, and your withdrawal lands hardest on the partner who championed you into the room. They should hear it from you, by voice, before any email exists.","task":"Say the 3-sentence phone opening to that partner.","tips":["The news first, then the cause — legal, final, not a negotiating position.","Say the thing that's true and hard: this costs them, and you know it.","Bring the salvage option: what your unit CAN still contribute without the agreement."],"focus":["audience","clarity"]},
    {"id":"hard-gov-mid-11","level":"mid","profession":"publicservice","title":"The failed probation conversation","scenario":"A probationary employee isn't meeting the standard — documented, coached, unchanged — and you're ending the appointment before probation closes. They're likable, trying hard, and not able to do this job. The conversation is ten minutes; the first thirty seconds must carry the decision.","task":"Say the first three sentences.","tips":["The decision in the first sentence — anything else is false hope with a countdown.","Effort acknowledged honestly, in one line; the standard is ability, and effort didn't close the gap.","Then immediately to logistics: last day, pay, references — concrete ground helps them stand."],"focus":["clarity","audience"]},
    {"id":"hard-gov-mid-12","level":"mid","profession":"publicservice","title":"The relocation nobody wants","scenario":"Your unit moves to the consolidated service centre in November — 40 minutes farther for half the team, announced from above, not reversible. Your team meeting message can't pretend it's good news, can't trash the decision you're implementing, and can't hide behind the memo. Straight, human, and forward is the needle.","task":"Write the 3-4 sentence announcement you'd deliver.","tips":["The fact and date first, plainly — spin is fuel for the resentment you're trying to manage.","Acknowledge the real cost out loud; naming it is the only thing that earns you the next sentence.","Then what you control: flex options, the commute survey, your commitment to fight for transition supports."],"focus":["clarity","audience"],"placeholder":"We're moving to the consolidated centre on Kent Street in November — that's decided, and for about half of us it adds real commute time. I won't pretend that part is good news. Here's what I can work with: flexible starts, the shuttle question, and —"},
    {"id":"hard-gov-mid-13","level":"mid","profession":"publicservice","title":"'The facility will not be rebuilt'","scenario":"The fire-damaged community hall won't be rebuilt — the assessment says the money serves more residents at the two nearby centres. You're delivering this at a public meeting in the neighbourhood that loved that hall. The decision is sound and the grief is real; the message has to hold both.","task":"Say the 3-4 sentence delivery of the decision.","tips":["Decision first, complete, no soft launch — the room already suspects it.","Acknowledge what the hall was; a paragraph of budget logic cannot precede one sentence of respect.","Then the concrete: what happens to the site, what the two centres add, and one channel for input that is genuinely still open."],"focus":["audience","impact"]},
    {"id":"hard-gov-mid-14","level":"mid","profession":"publicservice","title":"Owning the error to the councillor's office","scenario":"Your unit told a councillor's office a constituent's drainage issue was resolved. It wasn't — the work order was closed in error and the constituent just flooded again. The councillor's assistant is furious and the councillor is quoting your email. The response has one shot at containing this.","task":"Write the 3-sentence response: the error owned, the correction underway, and the process fix.","tips":["Own it in the first clause — 'our error' — before any explanation exists.","The correction needs a name, a date, and an hour: crew dispatched, tomorrow 8 a.m.","The process fix is what lets the assistant defend you upward; give them that sentence."],"focus":["clarity","impact"],"placeholder":"You were given wrong information and that's our error — the work order was closed without the repair being done. A crew is dispatched for tomorrow at 8 a.m. and I'll confirm completion to you personally. We've also changed the closure step so no order closes without —"},
    {"id":"hard-gov-mid-15","level":"mid","profession":"publicservice","title":"The position elimination conversation","scenario":"Restructuring eliminates a coordinator position, and its occupant — eleven years in the role — hears it from you tomorrow at 9 a.m. HR has scripted the legal parts. What HR can't script: the first two sentences, which decide whether the next hour is a conversation or a wound. No preamble about the weather. No 'how are you.'","task":"Say the first two sentences.","tips":["The news travels in sentence one; the reason — position eliminated, not performance — travels in sentence two.","'This isn't about your work' must be said early and be true.","Slow down; the sentences are short but the delivery isn't rushed. They will replay this hour for years."],"focus":["clarity","audience"]},
    {"id":"hard-gov-mid-16","level":"mid","profession":"publicservice","title":"The peer-to-peer dropped ball","scenario":"A peer supervisor's team missed the inspection handoff for the third time, and your unit absorbed the overtime. Going to their director first would be war; saying nothing subsidizes the pattern. The peer conversation needs the facts, the cost, and the ask — without a prosecutor's tone.","task":"Write the 3-sentence message to your peer.","tips":["Facts with dates, cost in hours or dollars — grievance without numbers reads as mood.","One ask, specific: a named handoff owner on their side.","Leave the escalation unsaid but real; peers hear it fine without the threat."],"focus":["precision","audience"],"placeholder":"The June 12 handoff was the third missed this quarter, and each one costs my team about six overtime hours to absorb. I need a named owner for the handoff on your side. Can we settle that this week?"},
    {"id":"hard-gov-mid-17","level":"mid","profession":"publicservice","title":"Turning down the internal transfer","scenario":"A solid team member applied for the vacancy in your other section and didn't get it — an external candidate was simply stronger. They'll suspect politics unless you tell them the real basis. The conversation owes them three things: the decision, the honest gap, and what would make them the pick next time.","task":"Say the 3-sentence core of that conversation.","tips":["No suspense: they didn't get it, said in the first breath.","The gap named specifically — case-management certification, panel scoring — kills the politics theory.","'Next time' is only kind if it's real; name the development step you'll actually support."],"focus":["clarity","precision"],"placeholder":"You didn't get the position — the panel scored an external candidate ahead of you, mainly on case-management certification. That gap is closable, and if you want it, I'll put the course in your development plan this year."},
    {"id":"hard-gov-mid-18","level":"mid","profession":"publicservice","title":"The service reduction, said plainly","scenario":"Weekend counter hours end in September — a budget decision, and your name is on the public notice. The draft you inherited hides the news under 'service delivery model enhancements' and 'channel optimization.' Residents losing their Saturday option deserve a sentence that says so.","task":"Write the 2-3 sentence public notice: the change, the reason, the alternatives.","tips":["Say what ends and when, in words a hurried reader can't misread.","One honest clause of reason — budget — beats a paragraph of 'optimization.'","The alternatives carry the message's usefulness: online, phone, and the weekday evening added."],"focus":["clarity","audience"],"placeholder":"Saturday counter service ends September 6 — a budget decision. Online and phone services continue unchanged, and we're adding Thursday evening hours until 7 p.m. for those who can't come weekdays."},
    {"id":"hard-gov-mid-19","level":"mid","profession":"publicservice","title":"Telling the director their option fails","scenario":"The director's preferred site for the new depot — floated publicly, half-promised to a councillor — fails the geotechnical review. You're the bearer. The message has to be unmissable about the finding, generous about the position it puts them in, and ready with the exit: the second site clears every test.","task":"Write the 3-sentence message.","tips":["Finding first, with its source: the geotech report, not your opinion.","No 'as I mentioned earlier' — being right earlier is a debt they can't pay right now.","Arrive with the door out: site two's numbers and a suggested line for the councillor."],"focus":["clarity","audience"],"placeholder":"The geotechnical report rules out the Mill Road site — remediation would run $2M over the project envelope. Site two on Carter Avenue passes every screen at budget. I've drafted a line for the councillor conversation if useful."},
    {"id":"hard-gov-mid-20","level":"mid","profession":"publicservice","title":"The safety write-up conversation","scenario":"An experienced operator bypassed the lockout procedure to save time — no injury, pure luck. The formal write-up is drafted; the conversation delivering it matters more than the paper. It has to land as deadly serious without theatrical anger, and it has to survive their 'I've done this a thousand times' defense.","task":"Say the 3-sentence delivery.","tips":["Name the act and the stake in the same breath: the bypass, and what it does to a person when luck runs out.","'A thousand times without injury' is the risk, not the defense — say that plainly.","The standard is absolute and impersonal: it protects them, their crew, and the next operator watching what veterans do."],"focus":["impact","clarity"]},
    {"id":"hard-gov-mid-21","level":"mid","profession":"publicservice","title":"Declining the councillor's ask","scenario":"A councillor's office asks you to 'expedite' a constituent's rezoning application — move it ahead of forty files ahead of it. The answer is no: one queue, statutory order, no discretion. Said wrong, you've made an enemy with a vote on your budget. Said right, you've taught their office how the queue protects them too.","task":"Write the 2-3 sentence decline.","tips":["The no rides on the rule, not on you: the queue is statutory and applies to every file.","Offer what's legitimately available: a status check, the accurate timeline, notice when it advances.","One sentence on why the rule serves them: the day the queue bends is the day it bends against their constituent."],"focus":["audience","clarity"],"placeholder":"I can't move the file up — the queue order is statutory and applies to all forty files ahead of it, which is also what protects your constituent's place from anyone else's phone call. What I can do today: an exact status, a realistic date, and a flag to your office the moment it advances."},
    {"id":"hard-gov-mid-22","level":"mid","profession":"publicservice","title":"The permit denial letter","scenario":"The street festival application fails on two hard requirements: no certified traffic-control plan and an insurance certificate at half the required coverage. The applicant is a first-time community organizer, not a professional events company. The denial has to be final about this application and genuinely open about the path back.","task":"Write the letter's first three sentences.","tips":["Denial first, then the two reasons as a checkable list, not a narrative.","Write the reasons as the reapplication instructions they secretly are.","The tone gap between 'rejected' and 'not yet approvable' is the difference between an angry call and a corrected resubmission."],"focus":["clarity","audience"],"placeholder":"Your application for the September 14 street festival is denied on two requirements: the traffic-control plan must be prepared by a certified provider, and liability coverage must be $5M (your certificate shows $2M). Both are fixable — and if you resubmit with them corrected by August 1, the date is still achievable."},
    {"id":"hard-gov-mid-23","level":"mid","profession":"publicservice","title":"After the termination, facing the team","scenario":"A team member was walked out yesterday — terminated for cause. The team saw the escort and the rumor mill is running. Privacy law caps what you can say at almost nothing, but saying nothing at all cedes the room to the worst version of the story. The briefing threads the needle: acknowledge, bound, redirect.","task":"Say the 3-sentence team briefing.","tips":["Confirm the departure as fact; everything about the cause stays sealed, and say why it stays sealed.","'The same privacy would protect each of you' converts frustration into understanding.","Redirect to the operational: coverage, reassignments, and your open door for what you CAN discuss."],"focus":["audience","precision"],"placeholder":"As you know, Jordan is no longer with the unit as of yesterday. I can't discuss the reasons — the same privacy rules would protect any of you, and I hold them for everyone. Here's how we're covering the files this month —"},
    {"id":"hard-gov-mid-24","level":"mid","profession":"publicservice","title":"Reversing your own call","scenario":"Three weeks ago you announced the new intake rotation with confidence. It isn't working — handoff errors doubled, and the team knows it before you've said it. Reversing course costs less than every alternative, and how you announce the reversal determines whether the team learns 'the boss adapts' or 'the boss flails.'","task":"Write the 3-sentence reversal announcement.","tips":["Own the original call and the evidence against it in the same breath — no passive voice, no scapegoat.","The reversal is a decision, announced with the same firmness as the original.","One line on what the experiment taught; a priced lesson reads as leadership, a buried one as luck."],"focus":["clarity","impact"],"placeholder":"I'm reversing the rotation change effective Monday — handoff errors doubled in three weeks, and the data beats my theory. We go back to paired intake, keeping the one piece that worked: the shared morning queue review."},
    {"id":"hard-gov-mid-25","level":"mid","profession":"publicservice","title":"The debrief finding about the veteran","scenario":"The evacuation debrief is unambiguous: the delay traced to a decision by the unit's most respected 25-year veteran — a call that made sense with the information she had at minute one and cost eleven minutes by minute twenty. The findings meeting includes her and her peers. Soften it into fog and the lesson dies; sharpen it into blame and the room dies.","task":"Say the 2-3 sentence delivery of that finding in the debrief.","tips":["State the finding as decision-plus-conditions: reasonable at the time made, costly as conditions changed.","The lesson is the system's: no re-evaluation trigger existed at the fifteen-minute mark — that's the fix.","Say her judgment isn't the finding; the missing trigger is. Precision here IS the kindness."],"focus":["precision","audience"]}
  ],
  "putting-it-together": [
    {"id":"together-gov-mid-01","level":"mid","profession":"publicservice","title":"The briefing note, end to end","scenario":"The deputy needs a one-page briefing note by 4 p.m.: a heating failure at the seniors' centre, 60 clients relocated, media calling, and a $90K emergency repair needing approval. Everything you've trained collapses into one page — the ask up front, the facts grouped, the numbers exact, nothing spare.","task":"Write the note's first four sentences: ask, situation, action taken, decision needed by when.","tips":["Sentence one carries the $90K ask and the 4 p.m. reason.","Group what happened into one tight situation sentence — the timeline is an attachment.","Every number checkable, every claim sourced; this page goes places you won't."],"focus":["structure","impact"],"placeholder":"Requesting approval today for $90K in emergency boiler replacement at the Lakeside Seniors' Centre. The system failed at 6 a.m.; all 60 clients were relocated to the Rec Complex by 9, with no injuries."},
    {"id":"together-gov-mid-02","level":"mid","profession":"publicservice","title":"One incident, three audiences","scenario":"A chlorine-handling error closed the pool for two days. Three messages now leave your desk: the director's notification, the staff briefing, and the public notice. Same facts — three completely different messages. Blur them together and each audience gets someone else's message.","task":"Write the first sentence of each of the three messages.","tips":["Director: incident, status, exposure — what they must know before their phone rings.","Staff: what changed in the procedure and who reviews it with them.","Public: closed until when, alternative where, no internal chemistry lesson."],"focus":["audience","structure"],"placeholder":"To the director: A chlorine-handling error closed Riverside Pool today; no injuries, two-day closure, procedure review underway. To staff: —"},
    {"id":"together-gov-mid-03","level":"mid","profession":"publicservice","title":"The sixty-second director update","scenario":"You pass the director in the corridor and get the words every supervisor knows: 'Walk with me — where are we on the inspection backlog?' Sixty seconds to deliver: status, trend, the one risk, and your ask. The full rubric at walking pace.","task":"Say the 4-sentence update.","tips":["Headline number first, with its direction: 180 files, down from 320.","One risk, one ask — the corridor can't carry more.","End before they reach the elevator; finishing early is the flex."],"focus":["concision","clarity"],"placeholder":"Backlog is 180, down from 320 in six weeks — on pace to clear by October. One risk: the two auditors seconded to me go back next month. If you can extend one of them, October holds."},
    {"id":"together-gov-mid-04","level":"mid","profession":"publicservice","title":"Same message, two registers","scenario":"The watermain project slips three weeks. Two messages must say so: a letter to affected residents and a memo to the ministry program office funding the work. Same fact, opposite registers — one warm and concrete, one precise and accountable. Writing them back-to-back is the register drill.","task":"Write the opening 2 sentences of each.","tips":["Residents: the delay in street-level terms — your water, your driveway, the new date.","Ministry: variance language with cause, milestone impact, and mitigation.","If the two openings could swap documents, neither is right yet."],"focus":["audience","precision"],"placeholder":"To residents: The Elm Street water project will finish October 3 — three weeks later than we told you, because the ground under the north block needed deeper repairs. To the ministry: This advises of a three-week schedule variance on Project W-2211 —"},
    {"id":"together-gov-mid-05","level":"mid","profession":"publicservice","title":"The pre-send checklist, applied","scenario":"Your draft memo requesting the enforcement blitz has been through four edits and feels done. Before it goes: does the first sentence carry the ask, is it grouped under one idea, can a third of the words go, are the claims specific, did you take a position? Run the five questions like an inspection.","task":"Audit the draft against the five checklist questions and write the three fixes an honest audit would order.","tips":["Read only your first sentence: could the director act on it alone?","Hunt vague claims — 'growing problem' fails; '34 complaints, up from 11' passes.","The word-count question is never optional; a third is almost always there."],"focus":["structure","concision"]},
    {"id":"together-gov-mid-06","level":"mid","profession":"publicservice","title":"The complaint file, closed properly","scenario":"A resident's complaint about a rude inspection took three weeks to investigate: partially substantiated — the inspector was curt, the citation itself was correct. The closing letter needs everything at once: the finding led plainly, the distinction kept precise, the apology specific, the citation standing, and the whole thing under 200 words.","task":"Write the letter's first three sentences.","tips":["Lead with the finding, both halves: conduct substantiated, citation valid.","The precision IS the fairness — don't let the apology blur into the citation.","Specific apology, named improvement, done; padding dilutes all three."],"focus":["precision","audience"],"placeholder":"We investigated both parts of your complaint. On the inspector's conduct, you were right — the exchange fell short of our standard, and that has been addressed with them directly. The citation itself was reviewed and stands: the deck rail measures —"},
    {"id":"together-gov-mid-07","level":"mid","profession":"publicservice","title":"The inter-agency proposal","scenario":"Your joint-dispatch proposal goes to three agency heads who have never agreed on anything. It needs the full stack in two pages: the shared problem in their common currency (response times), the before/after, the precise cost split, the strongest objection pre-answered, and one clean ask each. Two pages, three skeptics, one shot.","task":"Write the proposal's opening 3 sentences: shared problem, headline benefit, and the single ask.","tips":["Open on the number all three agencies already hate: the 40-minute cross-notification lag.","One benefit sentence with the modeled result — minutes saved, incidents covered.","Three asks means three meetings; one ask — sign the 90-day trial MOU — means a decision."],"focus":["impact","structure"],"placeholder":"Cross-agency notification currently averages 40 minutes on shared incidents — time all three of our services pay for in duplicated response. A joint dispatch protocol cuts it to under five. The ask today is one signature: a 90-day trial MOU."},
    {"id":"together-gov-mid-08","level":"mid","profession":"publicservice","title":"The first hour of the crisis","scenario":"A roof section collapsed at the arena during public skate — injuries unconfirmed, media inside eight minutes, staff phones already ringing. In the next hour you'll issue three communications in order: the internal alert, the director notification, and the public holding statement. Sequence, register, and discipline about the unknown — all at once, at speed.","task":"Write all three: one sentence each, in the order they'd go out.","tips":["Internal first: close, evacuate, route all media to you — command voice.","Director: facts confirmed so far, explicitly labelled unknowns, next update time.","Public holding: what happened, what's being done, when more comes — zero speculation about cause or casualties."],"focus":["clarity","structure"],"placeholder":"Internal: Evacuate the arena now, full closure, all media inquiries to me — confirmed. Director: Partial roof collapse at Central Arena during public skate; injuries unconfirmed, EMS on scene, next update within 30 minutes. Public: —"},
    {"id":"together-gov-mid-09","level":"mid","profession":"publicservice","title":"Opening statement, hostile committee","scenario":"You're before the oversight committee on the program overspend — five minutes of opening statement, then questions with knives out. The statement needs everything: the number owned up front, the causes precise, the fix concrete, the tone neither defensive nor grovelling. Every sentence will be clipped for the record.","task":"Write the opening three sentences of the statement.","tips":["Own the number in sentence one — the committee respects arithmetic delivered standing up.","Causes without adjectives; the word 'unprecedented' has died in this room a hundred times.","The fix with dates and a mechanism, so the questions start from your ground, not theirs."],"focus":["impact","precision"],"placeholder":"The program finished the year $340K over budget — 11% — and I'm here to account for it. Three drivers, in order of size: emergency shelter demand ran 22% above the funded forecast —"},
    {"id":"together-gov-mid-10","level":"mid","profession":"publicservice","title":"The year in one page","scenario":"Your unit's annual report to the division runs 30 pages of obligation. The covering page is the only one the deputy reads, and it's yours to design: the year's verdict sentence, three results with numbers, one honest miss, and next year's single priority. The whole discipline on one sheet.","task":"Write the covering page's five elements, one line each.","tips":["The verdict sentence takes a position on the year — not 'a year of challenges and opportunities.'","Each result: number, comparison, so-what, ten words if you can.","The honest miss, included by choice, is the line that makes the other four believable."],"focus":["concision","impact"],"placeholder":"Verdict: The unit did more with less until Q4, when 'less' won. Results: cleared 94% of inspections on standard (up from 81%) —"},
    {"id":"together-gov-mid-11","level":"mid","profession":"publicservice","title":"The hard news, spoken then written","scenario":"The teen drop-in program ends in June — you deliver it to staff in person at 2 p.m., and the confirming memo lands in inboxes at 4. Two artifacts, one message: the spoken version human and headline-first, the memo precise about dates and redeployment. If they diverge in substance, you'll pay for the gap.","task":"Write the spoken opening (2 sentences) and the memo's opening (2 sentences).","tips":["Spoken: the decision, then the acknowledgment — you're talking to people who built the thing.","Memo: decision, effective date, and the process facts — its job is to be quotable and exact.","Draft them together and check: same facts, same dates, different temperature."],"focus":["audience","clarity"]},
    {"id":"together-gov-mid-12","level":"mid","profession":"publicservice","title":"The rollout package","scenario":"The new complaint-intake procedure goes live in three weeks, and the rollout is yours: an all-staff announcement, a one-page quick-reference, and a talking point for supervisors' team meetings. Three artifacts, one change, each doing a different job — announce, enable, reinforce.","task":"Write the announcement's first two sentences and the quick-reference's first line.","tips":["Announcement: what changes, when, and the one-line why — benefit, not policy history.","Quick-reference: starts with the action in imperative voice, not background.","The supervisor talking point answers the question staff will actually ask: what happens to complaints already in the old system?"],"focus":["structure","audience"],"placeholder":"Announcement: Starting March 3, all complaints enter through the new intake form — one route, no more email side-doors, and a tracking number the resident gets instantly. Quick reference: 1. Open the intake form at —"},
    {"id":"together-gov-mid-13","level":"mid","profession":"publicservice","title":"The secondment handover","scenario":"You leave Monday for a six-month secondment, and your acting replacement — capable, new to the unit — inherits everything via your handover memo. The full stack in service of one reader: decisions they'll face grouped by type, the live risks with their tripwires, the three relationships that need tending, and where every body is buried.","task":"Write the memo's opening 3 sentences: the one-line mission, the top risk, and the first thing to do Monday morning.","tips":["Open with the unit's one-line mission as YOU hold it — orientation before inventory.","The top risk gets named with its tripwire and its escalation path.","'Monday morning, do this first' is the sentence they'll be most grateful for."],"focus":["structure","audience"],"placeholder":"The unit's job in one line: keep the inspection queue under 15 days without burning out nine people. Your top risk is the Fairview file — if the owner's lawyer calls, that's the tripwire; loop in Legal before responding."},
    {"id":"together-gov-mid-14","level":"mid","profession":"publicservice","title":"Choosing the channel","scenario":"Four messages sit in your drafts: a performance concern, a policy clarification, a thank-you to a partner agency, and a heads-up about a possible grievance. All four are drafted as emails. At least two shouldn't be — channel is part of the message, and email is the wrong room for some conversations.","task":"Assign each message its right channel and write the one-line rule you used.","tips":["Performance concerns and grievance-adjacent anything: voice first, paper after.","The thank-you gains value in public or in writing to their boss — choose deliberately.","Rule of thumb: email transmits information; conversations metabolize emotion. Match the load."],"focus":["audience","clarity"]},
    {"id":"together-gov-mid-15","level":"mid","profession":"publicservice","title":"The five-minute all-staff address","scenario":"The division head gave you five minutes at the all-staff to explain the service-model changes your unit pilots next quarter. Two hundred people, half suspicious, most of whom will remember one sentence. Structure, audience, stakes, and presence — live, no slides.","task":"Say the opening and closing sentences of the five minutes.","tips":["The opening earns the next four minutes: their day, changed for the better, in one sentence.","The middle is three signposted points; the close is the one sentence you want repeated at lunch.","Write the lunch sentence first, then build backward."],"focus":["audience","impact"]},
    {"id":"together-gov-mid-16","level":"mid","profession":"publicservice","title":"Rescuing the inherited notice","scenario":"Your predecessor's draft notice about the new dog-licensing enforcement is due out Friday: 300 words, passive throughout, the fee buried in paragraph four, the deadline in the last line, and a threatening tone that will generate more calls than compliance. Full-rubric rescue, one pass.","task":"Rewrite the notice as 3-4 sentences: what's required, by when, what it costs, what happens if not.","tips":["Requirement and deadline in sentence one; the reader decides in five seconds whether this applies to them.","Fee stated plainly — hiding it reads as trickery when it surfaces.","Consequence as fact, not threat; the fine prints identically either way, the tone doesn't."],"focus":["clarity","audience"],"placeholder":"All dogs must be licensed by April 30 — $25 per dog, online or at any service counter in ten minutes. After April 30, unlicensed dogs carry a $150 fine per inspection."},
    {"id":"together-gov-mid-17","level":"mid","profession":"publicservice","title":"The one-page business case","scenario":"The deputy's office announced spare year-end capital and gave every unit 48 hours to submit one-page cases. Yours: replacing the paper-based field inspection kit with tablets. One page against forty competing pages — the ask, the payback arithmetic, the risk of not, and the pilot evidence, all pulling together.","task":"Write the case's first three sentences.","tips":["The ask with its number and its payback period in sentence one — screeners sort by that.","One arithmetic chain, checkable: hours saved times rate times inspectors.","Your pilot data is the differentiator; forty pages will claim benefits, yours measured them."],"focus":["impact","precision"],"placeholder":"Requesting $46K for 12 field tablets — payback in 14 months from inspection-hours alone. The three-tablet pilot cut per-inspection paperwork from 25 minutes to 9, verified across 140 inspections."},
    {"id":"together-gov-mid-18","level":"mid","profession":"publicservice","title":"The update that died on arrival","scenario":"You're four sentences into your prepared backlog update when the director interrupts: 'That's not the question anymore — the ministry moved the audit to next month. What does THAT do to us?' Your prepared structure is rubble. Rebuild in real time: new headline, what you know, what you don't, when you'll know it.","task":"Say the 3-4 sentence pivoted answer.","tips":["Drop the script audibly — 'then the picture changes; here's what matters now' — and mean it.","Sort live: two things you know cold, one thing you don't, the date you'll know it.","Composure under a scrapped plan IS the executive presence being tested here."],"focus":["structure","clarity"]},
    {"id":"together-gov-mid-19","level":"mid","profession":"publicservice","title":"The apology that holds","scenario":"The department's error exposed 300 residents' contact details in a mailing mix-up. You're drafting the individual notification letter — an apology that must do everything at once: own the error plainly, say exactly what was and wasn't exposed, state the fix, and offer the next step. Legal wants hedges; the residents deserve English.","task":"Write the letter's first three sentences.","tips":["'We made an error' — subject, verb, ownership; 'an error occurred' is the passive that poisons everything after it.","Precision is the comfort: exactly what was exposed and exactly what wasn't.","The fix and the contact channel, concrete; 'we take privacy seriously' is filler that insults."],"focus":["clarity","audience"],"placeholder":"On June 3, our office made an error: a mailing list mix-up sent your name and street address to one other household in your area. No financial, health, or identification information was included — the exposure was limited to your name and address."},
    {"id":"together-gov-mid-20","level":"mid","profession":"publicservice","title":"The escalation memo","scenario":"You've flagged the ferry-dock corrosion twice through channels and it's still unfunded. This memo goes over your director's preferred pace, with their knowledge, to the capital committee — precision without alarmism, facts that compel without adjectives that accuse, and a paper trail cited without a grievance aired.","task":"Write the memo's first three sentences.","tips":["The condition, the standard it now fails, and the date it fails harder — arithmetic urgency.","Cite the prior flags as dates and file numbers, not as complaint.","Ask for a decision, not for sympathy: fund by X or accept documented risk Y."],"focus":["precision","impact"],"placeholder":"The Bay Street ferry dock's support pilings now measure below the structural standard's minimum on 4 of 12 points, and the engineer projects two more points fail by spring. This condition was flagged in capital submissions 2024-118 and 2025-097. The committee's decision point: fund the $410K repair this cycle, or —"},
    {"id":"together-gov-mid-21","level":"mid","profession":"publicservice","title":"The nomination that isn't generic","scenario":"You're nominating your intake coordinator for the division's service award. Every nomination the panel reads says 'goes above and beyond' and 'a true team player.' Persuasion plus precision applies to praise too: her actual numbers, one specific story, and the claim they add up to.","task":"Write the nomination's first three sentences.","tips":["Open with the claim, then prove it — same as any memo.","Numbers dignify praise: 96% file accuracy, 200 residents a month, zero escalations in a year.","One story with a date and a detail beats five superlatives; panels remember the blizzard shift, not the adjectives."],"focus":["precision","impact"],"placeholder":"Maria Santos has made the intake desk the most reliable point in this unit: 96% first-pass file accuracy across 2,400 files, zero escalated complaints in twelve months. One example carries the pattern: during the February blizzard —"},
    {"id":"together-gov-mid-22","level":"mid","profession":"publicservice","title":"Answering the audit in writing","scenario":"The auditor general's report criticizes your program on three findings: two fair, one based on a data error you can prove. The management response is public record. The full stack under oath: accept the fair findings specifically, correct the flawed one with evidence not indignation, and commit to fixes with dates.","task":"Write the response's first three sentences — one per finding.","tips":["Accepting a finding specifically ('finding 2 is accurate; the control was missing') earns you standing to contest finding 3.","Contest with the evidence and its source, in the flattest voice you own.","Every commitment carries a date and an owner; auditors return, and this document is what they mark you against."],"focus":["precision","structure"],"placeholder":"Management accepts findings 1 and 2: the reconciliation control described was not in place before March 2026, and has now been implemented. On finding 3, the underlying figure is incorrect — the cited caseload of 890 double-counts transferred files; the verified count is 512, per the attached extract."},
    {"id":"together-gov-mid-23","level":"mid","profession":"publicservice","title":"Coaching the draft, not rewriting it","scenario":"Your newest team lead sent you their first briefing note for review — buried lead, three ideas per paragraph, 'significant' four times. Rewriting it yourself is faster and teaches nothing. The coaching reply applies the whole rubric as questions they can run on every future draft.","task":"Write the 3-4 sentence coaching reply.","tips":["Lead with what works — find the real strength, name it specifically.","Convert each fix into a reusable question: 'What's the one thing the director must know? Make that sentence one.'","Cap it at three fixes; a checklist they'll reuse beats a markup they'll resent."],"focus":["audience","structure"],"placeholder":"Strong analysis — your section on the vendor risk is the best thinking in the note. Three questions to run on the next draft: What one sentence must the director act on? (Right now it's in paragraph four — move it to line one.)"},
    {"id":"together-gov-mid-24","level":"mid","profession":"publicservice","title":"Retiring the counter, launching the kiosk","scenario":"The cash-payment counter closes for good in October, replaced by kiosks and online payment — a change that genuinely helps most residents and genuinely hurts the few hundred who pay cash monthly. The public message needs every skill at once: the news plain, the benefit honest, the bridge for the cash payers concrete, the tone respectful of the loss.","task":"Write the 3-4 sentence public notice.","tips":["The change and date first; the benefit second, claimed honestly, not oversold.","The cash-payer bridge is the integrity test: name the exact alternative and where.","One sentence of respect for the people this costs — it's the difference between a notice and a brush-off."],"focus":["audience","clarity"],"placeholder":"The City Hall payment counter closes October 31; payments move to the kiosks in the lobby and online, both available around the clock. If you pay cash, you still can — the kiosks accept it, and staff will be beside them through November to walk you through the first one."},
    {"id":"together-gov-mid-25","level":"mid","profession":"publicservice","title":"The 11 p.m. message","scenario":"It's 11 p.m. and the encampment fire is out: one person hospitalized, stable; four displaced and sheltered; a propane rumor already on social media that your on-scene officer says is false. The deputy needs a message tonight that the mayor's office reads at 7 a.m. — everything you've practiced, no time to practice it, one draft that has to be right.","task":"Write the 4-sentence message: status, people, the rumor handled, next steps with times.","tips":["Confirmed facts in confirmed voice; the rumor addressed as 'reported, not supported by the scene assessment' — precision even at 11 p.m.","People before property, always — the hospitalized person leads.","Next steps with clock times give the 7 a.m. reader a machine already running; that's the whole message under the message."],"focus":["clarity","precision"],"placeholder":"The Lakeshore encampment fire is out; one person is in hospital in stable condition and four others are sheltered at the Grove Street facility tonight. Social media reports of a propane explosion are not supported by the on-scene assessment — the fire marshal investigates at first light."}
  ],
};
